                                                [class.bg-blue-50]="log.action.includes('止损') || log.action.includes('清')"
                                                [class.text-blue-700]="log.action.includes('止损') || log.action.includes('清')"
                                                [class.border-blue-200]="log.action.includes('止损') || log.action.includes('清')">
