type TradeAction = '建' | '加1' | '加2' | '止盈1' | '止盈2' | '止损' | '清仓' | '观察';

interface TradeLog {
  date: string;
  action: TradeAction;
  price: number;
  shares: number;
  amount: number;
  reason: string;
  pnlRatio?: number; 
  pnlAmount?: number;
  totalPosPercent: number; 
}

interface ChannelPoint {
  date: string;
  middle: number;
  top: number;
  bottom: number;
  slope: number;
}

interface BacktestStats {
  finalBalance: number;
  totalReturn: number;
  maxDrawdown: number;
  winRate: number;
  tradeCount: number;
  avgHoldDays: number;
  equityCurve: { date: string, value: number }[];
  marketTypeStats: {
     bull: { wins: number, total: number };
     bear: { wins: number, total: number };
     sideways: { wins: number, total: number };
  };
}

interface StrategyConfig {
  // 1. Time & Target
  etfCode: string;
  startDate: string;
  endDate: string;
