  // 5. Position
  posMode: 'PERCENT' | 'FIXED';
  posInitial: number; 
  posAdd1: number; 
  posAdd2: number; 
  posMax: number; 

  // 6. Stop/Profit
  stopLossPct: number; 
  takeProfitPct: number; 
}

