// Interfaces & Types
// ----------------------

type TradeAction = '建' | '加1' | '加2' | '止盈1' | '止盈2' | '止损' | '清仓' | '观察';

interface TradeLog {
  date: string;
  action: TradeAction;
  price: number;
  shares: number;
  amount: number;
  reason: string;
  pnlRatio?: number; 
  pnlAmount?: number;
  totalPosPercent: number; 
}

interface ChannelPoint {
  date: string;
  middle: number;
  top: number;
  bottom: number;
  slope: number;
}

interface BacktestStats {
  finalBalance: number;
  totalReturn: number;
  maxDrawdown: number;
  winRate: number;
  tradeCount: number;
  avgHoldDays: number;
  equityCurve: { date: string, value: number }[];
  marketTypeStats: {
     bull: { wins: number, total: number };
     bear: { wins: number, total: number };
     sideways: { wins: number, total: number };
  };
}

interface StrategyConfig {
  // 1. Time & Target
  etfCode: string;
  startDate: string;
  endDate: string;
  initialCapital: number;
  commission: number; 

  // 2. Parallel Trend
  trendShortN: number; 
  trendLongM: number; 
  trendSlopeThreshold: number; 

  // 3. Golden Fib
  fibCallback1: number; 
  fibCallback2: number; 
  fibExtension: number; 

  // 4. Volume
  volBreakoutRatio: number; 
  volShrinkRatio: number; 

  // 5. Position
  posMode: 'PERCENT' | 'FIXED';
  posInitial: number; 
  posAdd1: number; 
  posAdd2: number; 
  posMax: number; 

  // 6. Stop/Profit
  stopLossPct: number; 
  takeProfitPct: number; 
}

interface FibLevel {
  val: number;
  label: string;
  color: string;
  dash: string;
  isExtension?: boolean;
  isBase?: boolean;
  bgClass?: string;
  textClass?: string;
  borderClass?: string;
}

