                 </div>

                 <div class="border border-gray-100 rounded-lg p-3">
                    <h4 class="font-bold text-slate-800 mb-2">4. 止损与避险 (R9-R10)</h4>
                    <ul class="list-disc list-inside space-y-1 text-xs text-gray-500">
                        <li><strong>R9 防御</strong>: 跌破防御位 -> 当日预警，次日确认后减仓。</li>
                        <li><strong>R10 熔断</strong>: 跌破30日低点或巨幅跳空 -> 清仓。</li>
                    </ul>
                 </div>
              </div>
           </div>
           <div class="p-4 border-t border-gray-100 bg-gray-50 text-center">
              <button (click)="showRulesModal.set(false)" class="px-6 py-2 bg-slate-800 hover:bg-slate-700 text-white text-sm font-medium rounded-lg transition-colors">我已了解</button>
           </div>
        </div>
      </div>
    }
  `
})
export class RetracementComponent {
  private etfService = inject(EtfService);

  chartContainer = viewChild<ElementRef>('chartContainer');

  // --- State Signals ---
  isLoading = signal(false);
  errorMsg = signal<string | null>(null);
  showRulesModal = signal(false);

  config: StrategyConfig = {
    etfCode: '510300',
    startDate: '2020-01-01',
    endDate: new Date().toISOString().split('T')[0],
    initialCapital: 100000,
    commission: 0.0003,
    trendShortN: 10,
    trendLongM: 20,
    trendSlopeThreshold: 0.05, 
    fibCallback1: 0.382, // Standard Golden Ratio
    fibCallback2: 0.500, // Standard
    fibExtension: 1.0,
    volBreakoutRatio: 1.5,
    volShrinkRatio: 0.8,
    posMode: 'PERCENT',
    posInitial: 30, 
    posAdd1: 0.3, 
    posAdd2: 0.4, 
    posMax: 80, 
    stopLossPct: 0.05,
    takeProfitPct: 0.30
  };

  // Results
  result = signal<BacktestStats | null>(null);
  logs = signal<TradeLog[]>([]);
  chartData = signal<{history: KlinePoint[], markers: any[], channels: ChannelPoint[]} | null>(null);

  constructor() {
    effect(() => {
        const d = this.chartData();
        const container = this.chartContainer();
        if (d && container) {
            setTimeout(() => this.renderChart(d, container), 0);
        }
    });
  }

  resetConfig() {
      this.config = {
        ...this.config,
        trendShortN: 10, trendLongM: 20,
        fibCallback1: 0.382, fibCallback2: 0.500,
        volBreakoutRatio: 1.5, volShrinkRatio: 0.8,
        posMode: 'PERCENT', posInitial: 30, posAdd1: 0.3, posAdd2: 0.4, posMax: 80
      };
  }

  runBacktest() {
    if (!this.config.etfCode) return;
    this.isLoading.set(true);
    this.errorMsg.set(null);
    this.result.set(null);

    this.etfService.getBacktestData(this.config.etfCode).subscribe({
       next: (data) => {
          if (!data || data.history.length < 100) {
             this.errorMsg.set('数据不足，无法执行长周期回测');
             this.isLoading.set(false);
             return;
          }
          setTimeout(() => {
             this.executeStrategy(data.history);
             this.isLoading.set(false);
          }, 100);
       },
       error: () => {
          this.errorMsg.set('数据获取失败');
          this.isLoading.set(false);
       }
    });
  }

  // --- Core Strategy Logic (R0-R10) ---
  private executeStrategy(fullHistory: KlinePoint[]) {
     const history = fullHistory.filter(d => d.date >= this.config.startDate && d.date <= this.config.endDate);
     if (history.length < 50) {
         this.errorMsg.set('选定区间内数据不足');
         return;
     }

     let cash = this.config.initialCapital;
     let shares = 0;
     let entryPrice = 0; 
     const tradeLogs: TradeLog[] = [];
     const markers: any[] = [];
     const equityCurve: {date: string, value: number}[] = [];
     const channels: ChannelPoint[] = [];

     let waveHigh = -Infinity;
     let waveLow = Infinity;
     let entryIndex = -1;

     // Confirmation State Machines
     let daysBelowR6 = 0; // For R6 Take Profit Confirmation
     let daysBelowR9 = 0; // For R9 Stop Loss Confirmation

     // Linear Regression Channel Helper
     const M = this.config.trendLongM;

     const getSlopeAndChannel = (idx: number, period: number): {slope: number, top: number, bottom: number, middle: number} => {
         if (idx < period - 1) return { slope: 0, top: history[idx].high, bottom: history[idx].low, middle: history[idx].close };

         let sumX=0, sumY=0, sumXY=0, sumXX=0;
         const startIndex = idx - period + 1;

         for(let i=0; i<period; i++) {
             const p = history[startIndex + i];
             const x = i;
             const y = p.close;
             sumX += x; sumY += y; sumXY += x*y; sumXX += x*x;
         }

         const slope = (period * sumXY - sumX * sumY) / (period * sumXX - sumX * sumX);
         const intercept = (sumY - slope * sumX) / period;

         let maxDevHigh = -Infinity;
         let minDevLow = Infinity;

         for(let i=0; i<period; i++) {
             const p = history[startIndex + i];
             const regY = slope * i + intercept;
             maxDevHigh = Math.max(maxDevHigh, p.high - regY);
             minDevLow = Math.min(minDevLow, p.low - regY);
         }

         const currentX = period - 1;
         const currentMid = slope * currentX + intercept;

         return {
             slope: slope / history[idx].close, 
             middle: currentMid,
             top: currentMid + maxDevHigh,
             bottom: currentMid + minDevLow
         };
     };

     const buy = (idx: number, type: TradeAction, reason: string) => {
         const p = history[idx].close;
         let budget = 0;
         const totalAsset = cash + shares * p;

         if (type === '建') {
             if (this.config.posMode === 'FIXED') budget = this.config.posInitial;
             else budget = this.config.initialCapital * (this.config.posInitial / 100);
         } else if (type.includes('加')) {
             const initialBase = this.config.posMode === 'FIXED' ? this.config.posInitial : (this.config.initialCapital * this.config.posInitial/100);
             const multiplier = type === '加1' ? this.config.posAdd1 : this.config.posAdd2;
             budget = initialBase * multiplier;
         }

         const maxAsset = totalAsset * (this.config.posMax / 100);
         const currentPosVal = shares * p;
         if (currentPosVal >= maxAsset) return; 

         budget = Math.min(budget, cash);
         budget = Math.min(budget, maxAsset - currentPosVal);

         const tradeShares = Math.floor(budget / p / 100) * 100;
         if (tradeShares <= 0) return;

         const cost = tradeShares * p;
         const fee = cost * this.config.commission;

         if (cash < cost + fee) return;

         cash -= (cost + fee);
         entryPrice = (entryPrice * shares + cost) / (shares + tradeShares);
         shares += tradeShares;

         tradeLogs.push({
             date: history[idx].date, action: type, price: p, shares: tradeShares, amount: cost, reason,
             totalPosPercent: (shares*p)/(cash + shares*p)
         });
         markers.push({date: history[idx].date, type: 'BUY', label: type, price: p, reason: reason});

         if (type === '建') {
             waveHigh = p; 
             waveLow = history.slice(Math.max(0, idx-20), idx).reduce((min, cur) => Math.min(min, cur.low), Infinity);
             entryIndex = idx;
             daysBelowR6 = 0; // Reset counters
             daysBelowR9 = 0;
         }
     };

     const sell = (idx: number, type: TradeAction, reason: string, ratio: number = 1.0) => {
         if (shares === 0) return;
         const p = history[idx].close;
         const actualShares = Math.min(shares, Math.max(100, Math.floor(shares * ratio / 100) * 100));

         if (actualShares <= 0) return;

         const revenue = actualShares * p;
         const fee = revenue * this.config.commission;
         const cost = actualShares * entryPrice;
         const pnl = revenue - fee - cost;

         cash += (revenue - fee);
         shares -= actualShares;
         if (shares < 100) { 
             const dustRev = shares * p;
             cash += dustRev;
             shares = 0;
         }

         tradeLogs.push({
             date: history[idx].date, action: type, price: p, shares: actualShares, amount: revenue, reason,
             pnlAmount: pnl, pnlRatio: (p - entryPrice)/entryPrice * 100,
             totalPosPercent: (shares*p)/(cash + shares*p)
         });
         markers.push({date: history[idx].date, type: 'SELL', label: type, price: p, reason: reason});

         if (shares === 0) {
             waveHigh = -Infinity;
             daysBelowR6 = 0;
             daysBelowR9 = 0;
         }
     };

     for (let i = M; i < history.length; i++) {
         const today = history[i];
         const prev = history[i-1];

         // Update Wave Stats if Holding
         if (shares > 0) {
             if (today.high > waveHigh) waveHigh = today.high;
         }

         const channelInfo = getSlopeAndChannel(i, this.config.trendLongM);
         channels.push({ date: today.date, ...channelInfo });

         // Vol Stats
         const volAvg5 = history.slice(i-5, i).reduce((a,b)=>a+b.volume,0)/5;
         const prevVolAvg5 = history.slice(i-6, i-1).reduce((a,b)=>a+b.volume,0)/5;
         const isVolSpike = today.volume > this.config.volBreakoutRatio * volAvg5;
         const isPrevVolSpike = prev.volume > this.config.volBreakoutRatio * prevVolAvg5;

         // R0-R10 Logic

         // No Position
         if (shares === 0) {
             // R1: Entry (Breakout confirmed + Vol + Dip)
             const recentBreakout = (today.close > channelInfo.top || prev.close > channelInfo.top);
             const volConfirm = isVolSpike && isPrevVolSpike;

             if (recentBreakout && volConfirm && channelInfo.slope > 0) {
                 // Action: Buy if today is a dip (Close < Open or Close < PrevClose)
                 if (today.close < prev.close) {
                     buy(i, '建', 'R1:突破后回踩确认');
                 } 
             }
         } 
         // Holding Position
         else {
             const range = waveHigh - waveLow;
             const fib382 = waveHigh - range * 0.382;

             // R2: Add Position (Window 10 days, Fib Touch, Channel Support)
             if (i - entryIndex <= 10) {
                 const touchSupport = today.low <= channelInfo.middle * 1.01; 
                 const touchFib = (today.low <= fib382);
                 const isDip = today.close < prev.close;

                 const currentAdds = tradeLogs.filter(t => t.date > history[entryIndex].date && t.action.includes('加')).length;

                 if (touchFib && touchSupport && isDip && currentAdds < 2) {
                     buy(i, currentAdds === 0 ? '加1' : '加2', 'R2:时空共振加仓');
                 }
             }

             // R8: Hard Stop (Priority 1)
             if ((today.close - entryPrice)/entryPrice >= 0.30) {
                 sell(i, '清仓', 'R8:硬止盈(>30%)');
                 continue;
             }

             // R10: Extreme Cut (Priority 2)
             const low30 = Math.min(...history.slice(Math.max(0, i-30), i).map(d=>d.low));
             if (today.close < low30) {
                 sell(i, '清仓', 'R10:熔断止损');
                 continue;
             }

             // R6: Ladder Take Profit (T+2 Confirmation)
             const drop326 = waveHigh - range * 0.326;
             const drop618 = waveHigh - range * 0.618;
             const drop100 = waveHigh - range * 1.0;

             if (today.close < drop326) {
                 daysBelowR6++;
             } else {
                 daysBelowR6 = 0; // Reset if recovered
             }

             // Check Confirmation (Need 2 days pending, execute on 3rd fail?)
             // Rule: "T+2 Close not back, Next Day (T+3) Close < Level -> Sell"
             // Simplified: If below for > 2 days.
             if (daysBelowR6 >= 2) {
                 if (today.close < drop100) {
                     sell(i, '清仓', 'R6:有效跌破100%');
                 } else if (today.close < drop618) {
                     sell(i, '止盈2', 'R6:有效跌破61.8%', 25);
                 } else if (today.close < drop326) {
                     sell(i, '止盈1', 'R6:有效跌破32.6%', 25);
                 }
             }

             // R9: Defensive Stop (T+1 Confirmation)
             const stopLevel = entryPrice - range * 0.326; 
             if (today.close < stopLevel) {
                 daysBelowR9++;
             } else {
                 daysBelowR9 = 0;
             }

             if (daysBelowR9 >= 1) { // If yesterday was below (1) and today still below (now 2) -> Sell
                 sell(i, '止损', 'R9:防御位确认止损', 50);
             }
         }

         equityCurve.push({date: today.date, value: cash + shares * today.close});
     }

     const finalBal = equityCurve[equityCurve.length-1].value;
     let peak = this.config.initialCapital;
     let maxDd = 0;
     equityCurve.forEach(e => {
         if (e.value > peak) peak = e.value;
         const dd = (peak - e.value) / peak;
         if (dd > maxDd) maxDd = dd;
     });

     const winningTrades = tradeLogs.filter(t => t.pnlAmount && t.pnlAmount > 0).length;
     const totalTrades = tradeLogs.filter(t => t.pnlAmount !== undefined).length;

     this.logs.set(tradeLogs.reverse());
     this.chartData.set({ history, markers, channels });
     this.result.set({
         finalBalance: finalBal,
         totalReturn: (finalBal - this.config.initialCapital) / this.config.initialCapital * 100,
         maxDrawdown: maxDd * 100,
         winRate: totalTrades > 0 ? (winningTrades / totalTrades) * 100 : 0,
         tradeCount: totalTrades,
         avgHoldDays: totalTrades > 0 ? Math.floor(history.length / totalTrades / 2) : 0, 
         equityCurve,
         marketTypeStats: { bull: {wins:0,total:0}, bear: {wins:0,total:0}, sideways: {wins:0,total:0} }
     });
  }

  // --- D3 Chart ---
  private renderChart(data: {history: KlinePoint[], markers: any[], channels: ChannelPoint[]}, containerRef: ElementRef) {
     if (!data.history.length) return;
     try {
         const element = containerRef.nativeElement;
         d3.select(element).selectAll('*').remove();

         const { history, markers, channels } = data;

         const margin = { top: 20, right: 50, bottom: 30, left: 10 };
         const width = element.clientWidth - margin.left - margin.right;
         const height = element.clientHeight - margin.top - margin.bottom;

         const svg = d3.select(element).append('svg')
            .attr('width', width + margin.left + margin.right)
            .attr('height', height + margin.top + margin.bottom)
            .append('g')
            .attr('transform', `translate(${margin.left},${margin.top})`);

         // X Axis
         const x = d3.scaleBand()
            .domain(history.map(d => d.date))
            .range([0, width])
            .padding(0.2);

         const yMin = d3.min(history, d => d.low)! * 0.95;
         const yMax = d3.max(history, d => d.high)! * 1.05;
         const y = d3.scaleLinear().domain([yMin, yMax]).range([height, 0]);

         // Axes
         const xAxis = d3.axisBottom(x)
            .tickValues(x.domain().filter((d, i) => i % Math.floor(history.length / 6) === 0))
            .tickFormat(d => d.slice(2)); 

         svg.append('g').attr('transform', `translate(0,${height})`).call(xAxis).attr('class', 'text-gray-400 text-[10px]');
         svg.append('g').attr('transform', `translate(${width},0)`).call(d3.axisRight(y).ticks(5)).attr('class', 'text-gray-400 text-[10px]');

         // --- Draw Trend Channels (Background Ribbon) ---
         // We need to split channels into "Up" and "Down" segments to color them differently
         const channelSegments: { type: 'UP'|'DOWN', points: ChannelPoint[] }[] = [];
         let currentSegment: { type: 'UP'|'DOWN', points: ChannelPoint[] } | null = null;

         channels.forEach(pt => {
             const type = pt.slope >= 0 ? 'UP' : 'DOWN';
             if (!currentSegment || currentSegment.type !== type) {
                 if (currentSegment) channelSegments.push(currentSegment);
                 currentSegment = { type, points: [pt] };
             } else {
                 currentSegment.points.push(pt);
             }
         });
         if (currentSegment) channelSegments.push(currentSegment);

         const areaGen = d3.area<ChannelPoint>()
            .x(d => x(d.date)! + x.bandwidth()/2)
            .y0(d => y(d.bottom))
            .y1(d => y(d.top))
            .curve(d3.curveMonotoneX);

         const lineTop = d3.line<ChannelPoint>().x(d => x(d.date)! + x.bandwidth()/2).y(d => y(d.top)).curve(d3.curveMonotoneX);
         const lineBottom = d3.line<ChannelPoint>().x(d => x(d.date)! + x.bandwidth()/2).y(d => y(d.bottom)).curve(d3.curveMonotoneX);

         channelSegments.forEach(seg => {
             // Draw Fill
             svg.append('path')
                .datum(seg.points)
                .attr('fill', seg.type === 'UP' ? '#fecaca' : '#bbf7d0') // Red-200 / Green-200
                .attr('fill-opacity', 0.4)
                .attr('d', areaGen);

             // Draw Borders
             const borderColor = seg.type === 'UP' ? '#ef4444' : '#22c55e';
             svg.append('path').datum(seg.points).attr('fill', 'none').attr('stroke', borderColor).attr('stroke-width', 1).attr('stroke-dasharray', '2,2').attr('d', lineTop);
             svg.append('path').datum(seg.points).attr('fill', 'none').attr('stroke', borderColor).attr('stroke-width', 1).attr('stroke-dasharray', '2,2').attr('d', lineBottom);
         });

         // Candles
         const candles = svg.selectAll('.candle').data(history).enter().append('g');
         candles.append('line')
            .attr('x1', d => x(d.date)! + x.bandwidth()/2)
            .attr('x2', d => x(d.date)! + x.bandwidth()/2)
            .attr('y1', d => y(d.high)).attr('y2', d => y(d.low))
            .attr('stroke', d => d.close > d.open ? '#ef4444' : '#22c55e');
         candles.append('rect')
            .attr('x', d => x(d.date)!)
            .attr('y', d => y(Math.max(d.open, d.close)))
            .attr('width', x.bandwidth())
            .attr('height', d => Math.max(1, Math.abs(y(d.open) - y(d.close))))
            .attr('fill', d => d.close > d.open ? '#ef4444' : '#22c55e');

         // Markers
         markers.forEach(m => {
             const mx = x(m.date);
             if (mx === undefined) return;
             const cx = mx + x.bandwidth()/2;
             const cy = y(m.price);
             const isBuy = m.type === 'BUY';
             const color = isBuy ? '#10b981' : (m.label.includes('止盈') ? '#f97316' : '#3b82f6');

             svg.append('circle').attr('cx', cx).attr('cy', isBuy ? cy + 10 : cy - 10).attr('r', 4).attr('fill', color);
             svg.append('text').attr('x', cx).attr('y', isBuy ? cy + 22 : cy - 15)
                .text(m.label).attr('fill', color).attr('font-size', '9px').attr('text-anchor', 'middle').attr('font-weight', 'bold');
         });

         // Crosshair & Tooltip
         const crosshairX = svg.append('line').attr('stroke', '#94a3b8').attr('stroke-width', 1).attr('stroke-dasharray', '3,3').style('display', 'none').style('pointer-events', 'none');
         const crosshairY = svg.append('line').attr('stroke', '#94a3b8').attr('stroke-width', 1).attr('stroke-dasharray', '3,3').style('display', 'none').style('pointer-events', 'none');

         const tooltip = d3.select(element).append('div')
             .attr('class', 'chart-tooltip')
             .style('display', 'none')
             .style('pointer-events', 'none')
             .style('position', 'absolute')
             .style('z-index', '20')
             .style('background', 'rgba(255,255,255,0.95)')
             .style('padding', '8px')
             .style('border', '1px solid #e2e8f0')
             .style('border-radius', '4px')
             .style('box-shadow', '0 4px 6px -1px rgba(0, 0, 0, 0.1)')
             .style('font-size', '10px');

         svg.append('rect')
           .attr('width', width).attr('height', height)
           .attr('fill', 'transparent')
           .style('cursor', 'crosshair')
           .on('mousemove', (event) => {
               const [mx, my] = d3.pointer(event);
               const step = x.step();
               const index = Math.floor(mx / step);
               if (index >= 0 && index < history.length) {
                   const d = history[index];
                   const xPos = x(d.date)! + x.bandwidth()/2;

                   crosshairX.attr('x1', xPos).attr('x2', xPos).attr('y1', 0).attr('y2', height).style('display', null);
                   crosshairY.attr('x1', 0).attr('x2', width).attr('y1', my).attr('y2', my).style('display', null);

                   const m = markers.find(mark => mark.date === d.date);

                   let html = `<div class="font-bold mb-1">${d.date}</div>`;
                   html += `<div class="flex justify-between gap-4"><span>收盘:</span><span>${d.close.toFixed(3)}</span></div>`;
                   html += `<div class="flex justify-between gap-4"><span>涨跌:</span><span class="${d.close>d.open?'text-red-500':'text-green-500'}">${((d.close-d.open)/d.open*100).toFixed(2)}%</span></div>`;

                   if (m) {
                       html += `<div class="mt-2 pt-1 border-t border-gray-200 font-bold ${m.type==='BUY'?'text-red-600':'text-green-600'}">${m.label}</div>`;
                       if (m.reason) html += `<div class="text-gray-500 max-w-[150px] whitespace-normal">${m.reason}</div>`;
                   }

                   const box = element.getBoundingClientRect();
                   let left = mx + 20;
                   let top = my + 20;
                   if (left + 160 > width) left = mx - 150;

                   tooltip.html(html)
                     .style('display', 'block')
                     .style('left', `${left}px`)
                     .style('top', `${top}px`);
               } else {
                   crosshairX.style('display', 'none');
                   crosshairY.style('display', 'none');
                   tooltip.style('display', 'none');
               }
           })
           .on('mouseleave', () => {
               crosshairX.style('display', 'none');
               crosshairY.style('display', 'none');
               tooltip.style('display', 'none');
           });
     } catch(e) {
         console.warn('D3 Retracement Chart Error:', e);
     }
  }
}

import { Injectable, signal, inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { ETFDefinition, ETF_LIST } from './etf-list';
import { map, catchError, of, Observable, from, mergeMap, toArray, timeout, retry } from 'rxjs';

export interface KlinePoint {
  date: string;
  open: number;
  close: number;
  high: number;
  low: number;
  volume: number;
  amount: number;
  // Moving Averages
  ma5?: number;
  ma10?: number;
  ma20?: number;
  ma60?: number;
  // Slopes (Percentage Change per day)
  ma20Slope?: number;
  ma60Slope?: number;

  // Indicators
  macd?: { diff: number; dea: number; macd: number };
  kdj?: { k: number; d: number; j: number };
  rsi?: number;
  wr?: number; // Williams %R
  boll?: { upper: number; mid: number; lower: number; width: number }; 
  bias?: number; // BIAS 20

  // New Indicators
  atr?: number; // Average True Range (14)
  roc?: number; // Rate of Change
  mtm?: number; // Momentum
  obv?: number; // On-Balance Volume
  obvMa?: number; // MA of OBV
}

export interface FundBaseInfo {
  fundSize: number; // In Billions (亿元)
  establishmentDate: string; // YYYY-MM-DD
  age: number; // Years since establishment
}

export interface WaveStats {
  height: number;
  days: number;
  slope: number;
}

// Updated Trade Suggestion Types for Multi-period Resonance
export type TradeSuggestion = 
  'OBSERVE' |          // 观察点
  'BUY_POINT' |        // 建仓点
  'HOLD' |             // 持仓
  'TAKE_PROFIT_REDUCE' | // 止盈(减仓)
  'TAKE_PROFIT_CLEAR' |  // 止盈(清仓)
  'STOP_LOSS_REDUCE' |   // 止损(减仓)
  'STOP_LOSS_CLEAR' |    // 止损(清仓)
  'WAIT';              // 观望

export interface BoxSignal {
  type: 'UP' | 'DOWN';
  date: string; // Entry Date
  obsDate: string; // Observation Date
  boxHigh: number;
  boxLow: number;
  boxHeight: number;
  entryPrice: number;
  poc: number; // Point of Control
  tpA: number; // Target 38.2%
  tpB: number; // Target 61.8%
  slA: number; // Stop Loss 38.2%
  slB: number; // Stop Loss 61.8%
  clearPrice: number; // Clearance Point (Box Low)
  valid: boolean;
  boxStartDate: string; // For drawing box
}

export interface ETFAnalysis extends ETFDefinition, FundBaseInfo {
  currentPrice: number;
  suggestedEntryPrice: number; // Calculated Buy Target
  goldenPrice: number; // Golden Ratio Support Price (0.618 retracement)
  changePercent7d: number;
  isGolden: boolean; 
  breakMA5: boolean;
  breakMA20: boolean;
  breakDowntrend: boolean; 
  isHighVolume: boolean;

  // Counts
  buySignals: number;
  sellSignals: number;

  // Detailed Reasons
  buyFactors: string[];
  sellFactors: string[];

  trend: 'UP' | 'DOWN' | 'SIDEWAYS';
  score: number;
  health: number; // New Health Score
  symmetry?: {
      lastWave: WaveStats;
      currentSlope: number;
      slopeRatio: number; // current / last
  };

  suggestion: TradeSuggestion;
  boxSignal?: BoxSignal | null; // Multi-period Resonance Signal
  lastUpdated: string;
  history: KlinePoint[];
}

export interface FilterState {
  searchTerm: string;
  showFilters: boolean;
  filterGolden: boolean;
  filterHighVolume: boolean;
  filterBreakDowntrend: boolean;
  filterBreakMA5: boolean;
  filterBreakMA20: boolean;
  filterBreakMA20: boolean;
  filterTrend: string;
  filterIndustry: string; 
  filterSuggestion: string; // New Filter
  filterMinBuySignals: number;
  filterMinSellSignals: number;
  // New Filters
  filterMinScale: number; // Billion
  filterMinAge: number; // Years
  currentPage: number;
  sortField: string;
  sortDirection: 'asc' | 'desc';
}

export type DataSourceType = 'EASTMONEY' | 'TENCENT';

@Injectable({
  providedIn: 'root'
})
export class EtfService {
  private http: HttpClient = inject(HttpClient);

  // State
  loading = signal<boolean>(false);
  error = signal<string | null>(null);
  etfData = signal<ETFAnalysis[]>([]);
  dataSource = signal<DataSourceType>('EASTMONEY');

  // Favorites State
  favorites = signal<Set<string>>(new Set());
  private readonly FAV_STORAGE_KEY = 'etf_favorites_v1';
  private readonly DEFAULT_FAVORITES = [
    '512480', '512400', '513060', '159611', '515790', 
    '512660', '515000', '159995', '159819', '512800', 
    '512010', '512880', '515220', '510300', '510500', 
    '513180', '159941', '513500', '513880', '518880', '511260'
  ];

  // Available industries for filter dropdown
  availableIndustries = signal<string[]>(['宽基/指数','科技/TMT','医药/生物','大消费','新能源/车','金融','周期/资源','军工','债券','货币','其他']);

  // Filter State Persistence
  filterState = signal<FilterState>({
    searchTerm: '',
    showFilters: false,
    filterGolden: false,
    filterHighVolume: false,
    filterBreakDowntrend: false,
    filterBreakMA5: false,
    filterBreakMA20: false,
    filterTrend: 'ALL',
    filterIndustry: 'ALL',
    filterSuggestion: 'ALL',
    filterMinBuySignals: 0,
    filterMinSellSignals: 0,
    filterMinScale: 0,
    filterMinAge: 0,
    currentPage: 1,
    sortField: 'score',
    sortDirection: 'desc'
  });

  constructor() {
      this.loadFavorites();
  }

  private loadFavorites() {
      const stored = localStorage.getItem(this.FAV_STORAGE_KEY);
      if (stored) {
          try {
              const parsed = JSON.parse(stored);
              if (Array.isArray(parsed) && parsed.length > 0) {
                  this.favorites.set(new Set(parsed));
              } else {
                  this.favorites.set(new Set(this.DEFAULT_FAVORITES));
              }
          } catch (e) {
              this.favorites.set(new Set(this.DEFAULT_FAVORITES));
          }
      } else {
          this.favorites.set(new Set(this.DEFAULT_FAVORITES));
      }
  }

  toggleFavorite(code: string) {
      this.favorites.update(set => {
          const newSet = new Set(set);
          if (newSet.has(code)) {
              newSet.delete(code);
          } else {
              newSet.add(code);
          }
          localStorage.setItem(this.FAV_STORAGE_KEY, JSON.stringify(Array.from(newSet)));
          return newSet;
      });
  }

  isFavorite(code: string): boolean {
      return this.favorites().has(code);
  }

  updateFilterState(updates: Partial<FilterState>) {
    this.filterState.update(state => ({ ...state, ...updates }));
  }

  resetFilterState() {
     this.filterState.set({
        searchTerm: '',
        showFilters: false,
        filterGolden: false,
        filterHighVolume: false,
        filterBreakDowntrend: false,
        filterBreakMA5: false,
        filterBreakMA20: false,
        filterTrend: 'ALL',
        filterIndustry: 'ALL',
        filterSuggestion: 'ALL',
        filterMinBuySignals: 0,
        filterMinSellSignals: 0,
        filterMinScale: 0,
        filterMinAge: 0,
        currentPage: 1,
        sortField: 'score',
        sortDirection: 'desc'
     });
  }

  setDataSource(source: DataSourceType) {
    if (this.dataSource() === source) return;
    this.dataSource.set(source);

    // If we have data, just reload history
    const current = this.etfData();
    if (current.length > 0) {
        this.loading.set(true);
        this.fetchHistories(current);
    } else {
        this.loadAllEtfs();
    }
  }

  // Helpers
  private getMarketCode(code: string): string {
    if (code.startsWith('5') || code.startsWith('6')) return '1';
    return '0';
  }

  private getTencentCode(code: string): string {
      return (code.startsWith('5') || code.startsWith('6') ? 'sh' : 'sz') + code;
  }

  private classifyETF(name: string): string {
    if (/(300|500|1000|2000|50|100|800|创业板|科创|恒生|纳指|标普|红利|MSCI|综指|成指|大湾区|双创|中证|A50|道琼斯|日经|德国|法国|英国|东南亚|沙特)/.test(name)) return '宽基/指数';
    if (/(芯片|半导体|计算机|电子|5G|人工智能|游戏|传媒|通信|软件|科技|互联|AI|数据|卫星|信创|机器人|云计算|元宇宙|智能|信息|机床)/.test(name)) return '科技/TMT';
    if (/(医疗|药|生物|疫苗|医|健康|基因|中药)/.test(name)) return '医药/生物';
    if (/(酒|食品|家电|消费|旅游|养殖|农|畜|文娱|教育|美妆|饮料|乳)/.test(name)) return '大消费';
    if (/(光伏|电池|新能源|碳中和|车|绿电|电力|储能|环保|低碳|光电)/.test(name)) return '新能源/车';
    if (/(银行|券商|证券|保险|金融|FinTech|央企股东回报)/i.test(name)) return '金融';
    if (/(黄金|豆粕|有色|金属|稀土|铝|铜|矿|油|石化|煤炭|钢铁|能源|化工|基建|地产|房地产|建材|材料)/.test(name)) return '周期/资源';
    if (/(军工|国防|航天)/.test(name)) return '军工';
    if (/(债|政金|国开|同业存单)/.test(name)) return '债券';
    if (/(货币|理财|现金)/.test(name)) return '货币';
    return '其他';
  }

  private parseRawNumber(val: any): number {
    if (val === undefined || val === null || val === '-') return 0;
    if (typeof val === 'number') return val;
    return parseFloat(val) || 0;
  }

  // --- Main Methods ---

  /**
   * Load All ETFs Logic
   * Primary List Source: Eastmoney (Most reliable for lists)
   * History Source: Configurable (Eastmoney / Tencent)
   */
  loadAllEtfs() {
    if (this.loading()) return;
    this.loading.set(true);
    this.error.set(null);

    // Always use Eastmoney for the base list as it provides real-time snapshot + name + cap in one go
    const url = 'https://push2.eastmoney.com/api/qt/clist/get?pn=1&pz=2000&po=1&np=1&ut=bd1d9ddb04089700cf9c27f6f7426281&fltt=2&invt=2&wbp2u=|0|0|0|web&fid=f3&fs=b:MK0021&fields=f12,f13,f14,f2,f3,f4,f5,f6,f20,f21';

    this.http.jsonp<any>(url, 'cb').pipe(
        retry(1), 
        timeout(10000),
        catchError(err => {
            console.warn('Primary List API (Eastmoney) failed, switching to Fallback...', err);
            return this.loadFallbackEtfs();
        })
    ).subscribe({
        next: (res: any) => {
            if (res && res.data && res.data.diff) {
                this.processEastmoneyList(res.data.diff);
            } else if (Array.isArray(res)) {
                this.etfData.set(res);
                this.fetchHistories(res);
            } else {
                this.loadFallbackEtfs().subscribe(fallbackData => {
                    this.etfData.set(fallbackData);
                    this.fetchHistories(fallbackData);
                });
            }
        },
        error: (err) => {
            console.error('Final Load Error:', err);
            this.loadFallbackEtfs().subscribe(fallbackData => {
                this.etfData.set(fallbackData);
                this.loading.set(false);
            });
        }
    });
  }

  private processEastmoneyList(diff: any) {
      const rawList = Array.isArray(diff) ? diff : Object.values(diff);
      const marketDataMap = new Map<string, any>();
      rawList.forEach((item: any) => marketDataMap.set(item.f12, item));

      const baseAnalysis: ETFAnalysis[] = ETF_LIST.map(def => {
          const raw = marketDataMap.get(def.code);
          const price = raw ? this.parseRawNumber(raw.f2) : 0;
          let marketCap = raw ? this.parseRawNumber(raw.f20) : 0; 
          if (marketCap <= 0 && raw) marketCap = this.parseRawNumber(raw.f21);

          return this.createEtfItem(def, price, raw ? this.parseRawNumber(raw.f3) : 0, marketCap);
      });

      const validList = baseAnalysis.filter(e => e.currentPrice > 0);
      const finalList = validList.length > 0 ? validList : baseAnalysis;

      this.etfData.set(finalList);
      this.fetchHistories(finalList);
  }

  private loadFallbackEtfs(): Observable<ETFAnalysis[]> {
      return of(ETF_LIST.map(def => this.createEtfItem(def, 0, 0, 0))); 
  }

  private createEtfItem(def: ETFDefinition, price: number, pct: number, cap: number): ETFAnalysis {
      return {
        ...def,
        currentPrice: price,
        changePercent7d: pct, 
        isGolden: false,
        breakMA5: false,
        breakMA20: false,
        breakDowntrend: false,
        isHighVolume: false,
        buySignals: 0,
        sellSignals: 0,
        buyFactors: [],
        sellFactors: [],
        trend: 'SIDEWAYS',
        score: 50,
        health: 50,
        suggestion: 'WAIT',
        lastUpdated: new Date().toLocaleTimeString(),
        history: [],
        fundSize: cap / 100000000, 
        establishmentDate: '-',
        age: 0,
        suggestedEntryPrice: 0,
        goldenPrice: 0,
        industry: def.industry || this.classifyETF(def.name)
    };
  }

  private fetchHistories(currentList: ETFAnalysis[]) {
     from(currentList).pipe(
        mergeMap(item => this.fetchSingleHistory(item, 120), 4), 
        toArray()
     ).subscribe({
        next: (updatedList) => {
            this.etfData.update(current => {
               const map = new Map(updatedList.map(u => [u.code, u]));
               return current.map(c => map.get(c.code) || c);
            });
            this.loading.set(false);
        },
        error: (err) => {
            console.error('History Fetch Error:', err);
            this.loading.set(false); 
        }
     });
  }

  // --- History Fetch Strategy ---

  private fetchSingleHistory(item: ETFAnalysis, limit: number): Observable<ETFAnalysis> {
     const source = this.dataSource();
     if (source === 'TENCENT') {
         return this.fetchHistoryTencent(item, limit).pipe(
             catchError(err => {
                 // Fallback to Eastmoney if Tencent fails
                 console.warn(`Tencent history failed for ${item.code}, switching to Eastmoney fallback.`);
                 return this.fetchHistoryEastmoney(item, limit);
             })
         );
     } else {
         return this.fetchHistoryEastmoney(item, limit);
     }
  }

  // 1. Eastmoney
  private fetchHistoryEastmoney(item: ETFAnalysis, limit: number): Observable<ETFAnalysis> {
     const secid = `${this.getMarketCode(item.code)}.${item.code}`;
     const urlPrimary = `https://push2his.eastmoney.com/api/qt/stock/kline/get?secid=${secid}&fields1=f1,f2,f3,f4,f5,f6&fields2=f51,f52,f53,f54,f55,f56,f57,f58,f59,f60,f61&klt=101&fqt=1&end=20500101&lmt=${limit}`;

     return this.http.jsonp<any>(urlPrimary, 'cb').pipe(
        retry(1),
        timeout(8000),
        map((res: any) => {
            if (res && res.data && res.data.klines) {
                const history = this.parseEastmoneyKlines(res.data.klines);
                return this.analyzeETF(item, history);
            }
            throw new Error('No data from Primary');
        }),
        catchError(err => {
            // Fallback to PDFM if Primary fails
            return this.fetchHistoryFromPdfm(item, limit);
        })
     );
  }

  private fetchHistoryFromPdfm(item: ETFAnalysis, limit: number): Observable<ETFAnalysis> {
      const suffix = item.code.startsWith('5') || item.code.startsWith('6') ? '1' : '2';
      const id = `${item.code}${suffix}`;
      const token = '4f1862fc3b5e77c150a2b985b12db0fd'; 
      const url = `https://pdfm.eastmoney.com/EM_UBG_PDTI_Fast/api/js?rtntype=5&token=${token}&type=k&authorityType=&id=${id}`;

      return this.http.jsonp<any>(url, 'cb').pipe(
          timeout(5000),
          map((res: any) => {
              if (res && res.data && Array.isArray(res.data)) {
                  const rawLines = res.data;
                  const sliced = rawLines.slice(-limit);
                  const history = this.parseEastmoneyKlines(sliced);
                  return this.analyzeETF(item, history);
              }
              return item;
          }),
          catchError(() => of(item))
      );
  }

  // 2. Tencent (Web Interface)
  private fetchHistoryTencent(item: ETFAnalysis, limit: number): Observable<ETFAnalysis> {
      // URL: http://web.ifzq.gtimg.cn/appstock/app/fqkline/get?param=sh510300,day,,,320,qfq
      const tCode = this.getTencentCode(item.code);
      const url = `https://web.ifzq.gtimg.cn/appstock/app/fqkline/get?param=${tCode},day,,,${limit},qfq`;

      // Tencent returns a JSON object via callback.
      return this.http.jsonp<any>(url, 'callback').pipe(
          timeout(8000),
          map((res: any) => {
              if (res && res.data && res.data[tCode] && res.data[tCode].day) {
                  const dayData = res.data[tCode].day;
                  // Tencent Format: ["2023-01-01", "open", "close", "high", "low", "vol", ...]
                  const history: KlinePoint[] = dayData.map((d: any[]) => ({
                      date: d[0],
                      open: parseFloat(d[1]),
                      close: parseFloat(d[2]),
                      high: parseFloat(d[3]),
                      low: parseFloat(d[4]),
                      volume: parseFloat(d[5]),
                      amount: parseFloat(d[5]) * parseFloat(d[2]) // Estimate Amount as Vol * Close
                  }));
                  return this.analyzeETF(item, history);
              }
              // Throw error to trigger catchError in fetchSingleHistory
              throw new Error('Invalid Tencent Data');
          })
      );
  }

  getEtfDetails(code: string): Observable<ETFAnalysis | null> {
    const existing = this.etfData().find(e => e.code === code);
    if (existing && existing.history.length > 20) return of(existing);

    let def = ETF_LIST.find(e => e.code === code);
    if (!def) {
       def = { code, name: code, industry: '未知' };
    }

    const tempItem = this.createEtfItem(def, 0, 0, 0);
    return this.fetchSingleHistory(tempItem, 120);
  }

  getBacktestData(code: string): Observable<ETFAnalysis | null> {
      let def = ETF_LIST.find(e => e.code === code);
      if (!def) def = { code, name: code, industry: '未知' };
      const tempItem = this.createEtfItem(def, 0, 0, 0);
      return this.fetchSingleHistory(tempItem, 800);
  }

  // --- Parsing & Analysis ---

  private parseEastmoneyKlines(rawLines: string[]): KlinePoint[] {
    return rawLines.map(line => {
       const p = line.split(',');
       return {
          date: p[0],
          open: parseFloat(p[1]),
          close: parseFloat(p[2]),
          high: parseFloat(p[3]),
          low: parseFloat(p[4]),
          volume: parseFloat(p[5]),
          amount: parseFloat(p[6])
       };
    });
  }

  private calcBoxSignals(fullHistory: KlinePoint[]): BoxSignal | null {
      const minBoxSize = 30;
      if (fullHistory.length < minBoxSize + 5) return null;

      const scanLimit = Math.max(minBoxSize + 5, fullHistory.length - 60);

      for (let i = fullHistory.length - 1; i >= scanLimit; i--) {
          const entryDay = fullHistory[i];
          const confirmDay = fullHistory[i-1];
          const obsDay = fullHistory[i-2];

          const boxEndIdx = i - 2;
          const boxStartIdx = boxEndIdx - 29; 

          if (boxStartIdx < 0) continue;

          const boxData = fullHistory.slice(boxStartIdx, boxEndIdx + 1);
          const boxHigh = Math.max(...boxData.map(d => d.high));
          const boxLow = Math.min(...boxData.map(d => d.low));
          const D = boxHigh - boxLow;

          if (confirmDay.close > boxHigh && entryDay.close > boxHigh) {

             const prices = boxData.map(d => d.close);
             const minP = Math.min(...prices);
             const maxP = Math.max(...prices);
             const bins = 20;
             const binSize = (maxP - minP) / bins;
             let poc = (minP + maxP) / 2;

             if (binSize > 0) {
                 const binVols = new Array(bins).fill(0);
                 boxData.forEach(d => {
                    const idx = Math.min(bins-1, Math.floor((d.close - minP)/binSize));
                    binVols[idx] += d.volume;
                 });
                 const maxBinIdx = binVols.indexOf(Math.max(...binVols));
                 poc = minP + (maxBinIdx + 0.5) * binSize;
             }

             const volSlice = fullHistory.slice(i-5, i);
             const avgVol5 = volSlice.reduce((a,b)=>a+b.volume,0)/volSlice.length;

             const volSpike = entryDay.volume > 1.2 * avgVol5 || confirmDay.volume > 1.2 * avgVol5;
             const priceValid = entryDay.close > poc;

             if (priceValid && volSpike) {
                 return {
                     type: 'UP',
                     date: entryDay.date,
                     obsDate: obsDay.date,
                     entryPrice: entryDay.close,
                     boxStartDate: fullHistory[boxStartIdx].date,
                     boxHigh,
                     boxLow,
                     boxHeight: D,
                     poc,
                     tpA: entryDay.close + D * 0.382,
                     tpB: entryDay.close + D * 0.618,
                     slA: entryDay.close - D * 0.382,
                     slB: entryDay.close - D * 0.618,
                     clearPrice: boxLow, 
                     valid: true
                 };
             }
          }
      }
      return null;
  }

  private analyzeETF(item: ETFAnalysis, history: KlinePoint[]): ETFAnalysis {
     if (!history || history.length < 20) return { ...item, history };

     const points = this.calcIndicators(history);
     const latest = points[points.length - 1];
     const prev = points[points.length - 2];

     // Trend Analysis
     let trend: 'UP' | 'DOWN' | 'SIDEWAYS' = 'SIDEWAYS';
     if (latest.ma20 && prev.ma20) {
        if (latest.close > latest.ma20 && latest.ma20 > prev.ma20) trend = 'UP';
        else if (latest.close < latest.ma20 && latest.ma20 < prev.ma20) trend = 'DOWN';
     }

     const volAvg5 = points.slice(-5).reduce((a, b) => a + b.volume, 0) / 5;
     const isHighVolume = latest.volume > 1.5 * volAvg5;

     // Base Signals
     let buySignals = 0;
     let sellSignals = 0;
     const buyFactors: string[] = [];
     const sellFactors: string[] = [];

     const breakMA5 = latest.close < (latest.ma5 || 0);
     const breakMA20 = latest.close < (latest.ma20 || 0);
     const breakDowntrend = prev.close < (prev.ma20 || 0) && latest.close > (latest.ma20 || 0);

     if (breakDowntrend) { buySignals++; buyFactors.push('突破20日均线'); }
     if (isHighVolume && latest.close > latest.open) { buySignals++; buyFactors.push('放量上涨'); }

     // Golden Ratio
     const recent = points.slice(-30);
     const maxHigh = Math.max(...recent.map(p => p.high));
     const minLow = Math.min(...recent.map(p => p.low));
     const range = maxHigh - minLow;
     const goldenPrice = maxHigh - range * 0.382;
     const isGolden = Math.abs(latest.close - goldenPrice) / goldenPrice < 0.02;

     if (isGolden && trend === 'UP') { buySignals += 2; buyFactors.push('黄金分割支撑位'); }

     // MACD
     if (latest.macd && prev.macd) {
        if (latest.macd.macd > 0 && prev.macd.macd <= 0) { buySignals += 2; buyFactors.push('MACD金叉'); }
        if (latest.macd.macd < 0 && prev.macd.macd >= 0) { sellSignals += 2; sellFactors.push('MACD死叉'); }
     }

     if (breakMA20) { sellSignals++; sellFactors.push('跌破20日均线'); }

     // --- Enhanced Signal Logic ---
     // 1. Moving Averages Alignment
     if (latest.ma5 && latest.ma10 && latest.ma20) {
         if (latest.ma5 > latest.ma10 && latest.ma10 > latest.ma20) {
             buySignals++; buyFactors.push('均线多头排列');
         }
         if (latest.ma5 < latest.ma10 && latest.ma10 < latest.ma20) {
             sellSignals++; sellFactors.push('均线空头排列');
         }
     }

     // 2. RSI
     if (latest.rsi) {
         if (latest.rsi < 30) { buySignals++; buyFactors.push('RSI超卖区'); }
         if (latest.rsi > 70) { sellSignals++; sellFactors.push('RSI超买区'); }
     }

     // 3. KDJ
     if (latest.kdj && prev.kdj) {
         if (prev.kdj.k < prev.kdj.d && latest.kdj.k > latest.kdj.d && latest.kdj.d < 50) {
             buySignals++; buyFactors.push('KDJ低位金叉');
         }
         if (prev.kdj.k > prev.kdj.d && latest.kdj.k < latest.kdj.d && latest.kdj.d > 50) {
             sellSignals++; sellFactors.push('KDJ高位死叉');
         }
     }

     // 4. MA60 Trend
     if (latest.ma60) {
         if (latest.close > latest.ma60 && prev.close <= prev.ma60) {
             buySignals++; buyFactors.push('站上60日均线');
         }
         if (latest.close < latest.ma60 && prev.close >= prev.ma60) {
             sellSignals++; sellFactors.push('跌破60日均线');
         }
     }

     // Box Signal Calculation
     const boxSignal = this.calcBoxSignals(points);

     // --- NEW SCORING MODEL (0-100) ---

     // 1. Trend (35%)
     let trendScore = 0;
     const ma5 = latest.ma5 || 0;
     const ma10 = latest.ma10 || 0;
     const ma20 = latest.ma20 || 0;
     const ma60 = latest.ma60 || 0;

     if (ma5 > ma10 && ma10 > ma20) trendScore += 15;
     if (ma20 > ma60) trendScore += 15;
     if (latest.close > ma20) trendScore += 10;
     if (latest.close > ma60) trendScore += 10;
     if ((latest.ma20Slope || 0) > 0) trendScore += 10;
     if ((latest.ma60Slope || 0) > 0) trendScore += 10;
     trendScore = Math.min(35, trendScore * (35/70));

     // 2. Momentum (30%)
     let momScore = 0;
     const macdVal = latest.macd?.macd || 0;
     const diff = latest.macd?.diff || 0;
     const dea = latest.macd?.dea || 0;
     if (macdVal > 0) momScore += 10;
     if (diff > dea) momScore += 10;

     const rsiVal = latest.rsi || 50;
     if (rsiVal > 50 && rsiVal < 80) momScore += 10;
     if (rsiVal >= 80) momScore -= 5;

     const k = latest.kdj?.k || 50;
     const dVal = latest.kdj?.d || 50;
     if (k > dVal) momScore += 10;
     if ((latest.roc || 0) > 0) momScore += 10;
     momScore = Math.min(30, momScore * (30/50));

     // 3. Volatility (15%)
     let volScore = 0;
     const wr = latest.wr || -50;
     if (wr > -80 && wr < -20) volScore += 10; 
     const bias = latest.bias || 0;
     if (bias > 0 && bias < 5) volScore += 10; 
     const boll = latest.boll;
     if (boll && latest.close > boll.mid && latest.close < boll.upper) volScore += 10;
     volScore = Math.min(15, volScore * (15/30));

     // 4. Volume (20%)
     let volumeScore = 0;
     if (latest.obv && latest.obvMa && latest.obv > latest.obvMa) volumeScore += 15;
     if (latest.volume > volAvg5) volumeScore += 10;
     if (latest.close > latest.open) volumeScore += 5; 
     volumeScore = Math.min(20, volumeScore * (20/30));

     // Total Score
     let finalScore = trendScore + momScore + volScore + volumeScore;

     // Bonus for Box Signal
     if (boxSignal && boxSignal.valid) {
         if (latest.close > boxSignal.entryPrice && latest.close < boxSignal.tpA) {
             finalScore += 15;
             buyFactors.push('箱体突破共振(Box Breakout)');
         }
     }

     if (rsiVal > 85) finalScore -= 10;
     if (trend === 'DOWN') finalScore -= 15;
     finalScore = Math.max(0, Math.min(100, Math.round(finalScore)));

     // Trade Suggestion Logic
     let suggestion: TradeSuggestion = 'WAIT';

     if (boxSignal && boxSignal.valid) {
         const p = latest.close;
         if (p < boxSignal.clearPrice) {
             suggestion = 'STOP_LOSS_CLEAR';
             sellFactors.push('跌破箱体下沿(Clearance)');
             finalScore = Math.min(finalScore, 20);
         }
         else if (p < boxSignal.slB) {
             suggestion = 'STOP_LOSS_CLEAR';
             sellFactors.push('触及止损B线');
             finalScore = Math.min(finalScore, 20);
         }
         else if (p < boxSignal.slA) {
             suggestion = 'STOP_LOSS_REDUCE';
             sellFactors.push('触及止损A线');
             finalScore = Math.min(finalScore, 30);
         }
         else if (p >= boxSignal.tpB) {
             suggestion = 'TAKE_PROFIT_CLEAR';
             sellFactors.push('达到止盈B目标');
         }
         else if (p >= boxSignal.tpA) {
             suggestion = 'TAKE_PROFIT_REDUCE';
             sellFactors.push('达到止盈A目标');
         }
         else if (p > boxSignal.entryPrice) {
             suggestion = 'HOLD';
         }
         else {
             suggestion = 'BUY_POINT';
         }
     } else {
         if (finalScore >= 80) suggestion = 'BUY_POINT';
         else if (finalScore >= 60) suggestion = 'HOLD';
         else if (finalScore <= 35) suggestion = 'STOP_LOSS_REDUCE';
         else if (finalScore <= 20) suggestion = 'STOP_LOSS_CLEAR';
     }

     return {
        ...item,
        currentPrice: latest.close,
        changePercent7d: (latest.close - (points[points.length - 6]?.close || latest.close)) / (points[points.length - 6]?.close || 1) * 100,
        isGolden,
        goldenPrice,
        breakMA5,
        breakMA20,
        breakDowntrend,
        isHighVolume,
        buySignals,
        sellSignals,
        buyFactors,
        sellFactors,
        trend,
        score: finalScore,
        health: Math.floor(finalScore * 0.8 + Math.random() * 15),
        suggestion,
        boxSignal,
        lastUpdated: new Date().toLocaleTimeString(),
        history: points,
        suggestedEntryPrice: goldenPrice
     };
  }

  private calcIndicators(data: KlinePoint[]): KlinePoint[] {
      const results: KlinePoint[] = [];

      let ema12 = 0;
      let ema26 = 0;
      let dea = 0;
      let atr = 0;
      let avgGain = 0;
      let avgLoss = 0;
      let kValue = 50;
      let dValue = 50;
      let obv = 0;
      const obvHistory: number[] = [];

      for (let i = 0; i < data.length; i++) {
          const d = data[i];
          const close = d.close;
          const prev = i > 0 ? data[i-1] : null;

          // --- MAs ---
          const calcMa = (n: number) => {
              if (i < n - 1) return undefined;
              let sum = 0;
              for(let k=0; k<n; k++) sum += data[i-k].close;
              return sum / n;
          };
          const ma5 = calcMa(5);
          const ma10 = calcMa(10);
          const ma20 = calcMa(20);
          const ma60 = calcMa(60);

          let ma20Slope = 0;
          let ma60Slope = 0;
          if (i > 20 && ma20 && results[i-1]?.ma20) {
              ma20Slope = (ma20 - results[i-1].ma20!) / results[i-1].ma20! * 100;
          }
          if (i > 60 && ma60 && results[i-1]?.ma60) {
              ma60Slope = (ma60 - results[i-1].ma60!) / results[i-1].ma60! * 100;
          }

          // --- MACD ---
          if (i === 0) {
              ema12 = close;
              ema26 = close;
          } else {
              ema12 = (2 * close + 11 * ema12) / 13;
              ema26 = (2 * close + 25 * ema26) / 27;
          }
          const diff = ema12 - ema26;
          if (i === 0) dea = diff;
          else dea = (2 * diff + 8 * dea) / 10;
          const macd = 2 * (diff - dea);

          // --- ATR ---
          if (i === 0) atr = d.high - d.low;
          else {
              const tr = Math.max(d.high - d.low, Math.abs(d.high - prev!.close), Math.abs(d.low - prev!.close));
              atr = (atr * 13 + tr) / 14;
          }

          // --- BOLL ---
          let boll = undefined;
          if (ma20 && i >= 19) {
              let sumSq = 0;
              for (let k=0; k<20; k++) sumSq += Math.pow(data[i-k].close - ma20, 2);
              const std = Math.sqrt(sumSq / 20);
              boll = { upper: ma20 + 2 * std, mid: ma20, lower: ma20 - 2 * std, width: (4*std)/ma20 };
          }

          // --- RSI ---
          let rsi = undefined;
          if (i > 0) {
              const change = close - prev!.close;
              const gain = change > 0 ? change : 0;
              const loss = change < 0 ? -change : 0;
              if (i < 14) {
                  if (i === 1) { avgGain = gain; avgLoss = loss; }
                  else {
                      avgGain = (avgGain * (i-1) + gain) / i;
                      avgLoss = (avgLoss * (i-1) + loss) / i;
                  }
              } else {
                   avgGain = (avgGain * 13 + gain) / 14;
                   avgLoss = (avgLoss * 13 + loss) / 14;
                   if (avgLoss === 0) rsi = 100;
                   else rsi = 100 - (100 / (1 + avgGain / avgLoss));
              }
          }

          // --- KDJ ---
          let kdj = undefined;
          if (i >= 8) {
              let lowest = d.low;
              let highest = d.high;
              for(let j=0; j<9; j++) {
                  lowest = Math.min(lowest, data[i-j].low);
                  highest = Math.max(highest, data[i-j].high);
              }
              const rsv = (highest === lowest) ? 50 : (close - lowest) / (highest - lowest) * 100;
              kValue = (2/3) * kValue + (1/3) * rsv;
              dValue = (2/3) * dValue + (1/3) * kValue;
              kdj = { k: kValue, d: dValue, j: 3 * kValue - 2 * dValue };
          }

          // --- WR (14) ---
          let wr = undefined;
          if (i >= 13) {
              let h14 = -Infinity;
              let l14 = Infinity;
              for(let j=0; j<14; j++) {
                  h14 = Math.max(h14, data[i-j].high);
                  l14 = Math.min(l14, data[i-j].low);
              }
              wr = (h14 === l14) ? -50 : (h14 - close) / (h14 - l14) * -100;
          }

          // --- BIAS (20) ---
          let bias = undefined;
          if (ma20) bias = (close - ma20) / ma20 * 100;

          // --- ROC (12) ---
          let roc = undefined;
          if (i >= 12) {
              const ref = data[i-12].close;
              if (ref) roc = (close - ref) / ref * 100;
          }

          // --- MTM (12) ---
          let mtm = undefined;
          if (i >= 12) {
              mtm = close - data[i-12].close;
          }

          // --- OBV ---
          if (i > 0) {
              if (close > prev!.close) obv += d.volume;
              else if (close < prev!.close) obv -= d.volume;
          }
          obvHistory.push(obv);

          let obvMa = undefined;
          if (i >= 29) {
              let sumObv = 0;
              for(let k=0; k<30; k++) sumObv += obvHistory[i-k];
              obvMa = sumObv / 30;
          }

          results.push({
              ...d,
              ma5, ma10, ma20, ma60,
              ma20Slope, ma60Slope,
              macd: { diff, dea, macd },
              atr, boll, rsi, kdj,
              wr, bias, roc, mtm,
              obv, obvMa
          });
      }
      return results;
  }
}

import { Injectable, signal, inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { ETFDefinition, ETF_LIST } from './etf-list';
import { map, catchError, of, Observable, from, mergeMap, toArray, timeout, retry } from 'rxjs';

export interface KlinePoint {
  date: string;
  open: number;
  close: number;
  high: number;
  low: number;
  volume: number;
  amount: number;
  // Moving Averages
  ma5?: number;
  ma10?: number;
  ma20?: number;
  ma60?: number;
  // Slopes (Percentage Change per day)
  ma20Slope?: number;
  ma60Slope?: number;

  // Indicators
  macd?: { diff: number; dea: number; macd: number };
  kdj?: { k: number; d: number; j: number };
  rsi?: number;
  wr?: number; // Williams %R
  boll?: { upper: number; mid: number; lower: number; width: number }; 
  bias?: number; // BIAS 20

  // New Indicators
  atr?: number; // Average True Range (14)
  roc?: number; // Rate of Change
  mtm?: number; // Momentum
  obv?: number; // On-Balance Volume
  obvMa?: number; // MA of OBV
}

export interface FundBaseInfo {
  fundSize: number; // In Billions (亿元)
  establishmentDate: string; // YYYY-MM-DD
  age: number; // Years since establishment
}

export interface WaveStats {
  height: number;
  days: number;
  slope: number;
}

// Updated Trade Suggestion Types for Multi-period Resonance
export type TradeSuggestion = 
  'OBSERVE' |          // 观察点
  'BUY_POINT' |        // 建仓点
  'HOLD' |             // 持仓
  'TAKE_PROFIT_REDUCE' | // 止盈(减仓)
  'TAKE_PROFIT_CLEAR' |  // 止盈(清仓)
  'STOP_LOSS_REDUCE' |   // 止损(减仓)
  'STOP_LOSS_CLEAR' |    // 止损(清仓)
  'WAIT';              // 观望

export interface BoxSignal {
  type: 'UP' | 'DOWN';
  date: string; // Entry Date
  obsDate: string; // Observation Date
  boxHigh: number;
  boxLow: number;
  boxHeight: number;
  entryPrice: number;
  poc: number; // Point of Control
  tpA: number; // Target 38.2%
  tpB: number; // Target 61.8%
  slA: number; // Stop Loss 38.2%
  slB: number; // Stop Loss 61.8%
  clearPrice: number; // Clearance Point (Box Low)
  valid: boolean;
  boxStartDate: string; // For drawing box
}

export interface ETFAnalysis extends ETFDefinition, FundBaseInfo {
  currentPrice: number;
  suggestedEntryPrice: number; // Calculated Buy Target
  goldenPrice: number; // Golden Ratio Support Price (0.618 retracement)
  changePercent7d: number;
  isGolden: boolean; 
  breakMA5: boolean;
  breakMA20: boolean;
  breakDowntrend: boolean; 
  isHighVolume: boolean;

  // Counts
  buySignals: number;
  sellSignals: number;

  // Detailed Reasons
  buyFactors: string[];
  sellFactors: string[];

  trend: 'UP' | 'DOWN' | 'SIDEWAYS';
  score: number;
  health: number; // New Health Score
  symmetry?: {
      lastWave: WaveStats;
      currentSlope: number;
      slopeRatio: number; // current / last
  };

  suggestion: TradeSuggestion;
  boxSignal?: BoxSignal | null; // Multi-period Resonance Signal
  lastUpdated: string;
  history: KlinePoint[];
}

export interface FilterState {
  searchTerm: string;
  showFilters: boolean;
  filterGolden: boolean;
  filterHighVolume: boolean;
  filterBreakDowntrend: boolean;
  filterBreakMA5: boolean;
  filterBreakMA20: boolean;
  filterTrend: string;
  filterIndustry: string; 
  filterSuggestion: string; // New Filter
  filterMinBuySignals: number;
  filterMinSellSignals: number;
  // New Filters
  filterMinScale: number; // Billion
  filterMinAge: number; // Years
  currentPage: number;
  sortField: string;
  sortDirection: 'asc' | 'desc';
}

export type DataSourceType = 'EASTMONEY' | 'TENCENT';

@Injectable({
  providedIn: 'root'
})
export class EtfService {
  private http: HttpClient = inject(HttpClient);

  // State
  loading = signal<boolean>(false);
  error = signal<string | null>(null);
  etfData = signal<ETFAnalysis[]>([]);
  dataSource = signal<DataSourceType>('EASTMONEY');

  // Favorites State
  favorites = signal<Set<string>>(new Set());
  private readonly FAV_STORAGE_KEY = 'etf_favorites_v1';
  private readonly DEFAULT_FAVORITES = [
    '512480', '512400', '513060', '159611', '515790', 
    '512660', '515000', '159995', '159819', '512800', 
    '512010', '512880', '515220', '510300', '510500', 
    '513180', '159941', '513500', '513880', '518880', '511260'
  ];

  // Available industries for filter dropdown
  availableIndustries = signal<string[]>(['宽基/指数','科技/TMT','医药/生物','大消费','新能源/车','金融','周期/资源','军工','债券','货币','其他']);

  // Filter State Persistence
  filterState = signal<FilterState>({
    searchTerm: '',
    showFilters: false,
    filterGolden: false,
    filterHighVolume: false,
    filterBreakDowntrend: false,
    filterBreakMA5: false,
    filterBreakMA20: false,
    filterTrend: 'ALL',
    filterIndustry: 'ALL',
    filterSuggestion: 'ALL',
    filterMinBuySignals: 0,
    filterMinSellSignals: 0,
    filterMinScale: 0,
    filterMinAge: 0,
    currentPage: 1,
    sortField: 'score',
    sortDirection: 'desc'
  });

  constructor() {
      this.loadFavorites();
  }

  private loadFavorites() {
      const stored = localStorage.getItem(this.FAV_STORAGE_KEY);
      if (stored) {
          try {
              const parsed = JSON.parse(stored);
              if (Array.isArray(parsed) && parsed.length > 0) {
                  this.favorites.set(new Set(parsed));
              } else {
                  this.favorites.set(new Set(this.DEFAULT_FAVORITES));
              }
          } catch (e) {
              this.favorites.set(new Set(this.DEFAULT_FAVORITES));
          }
      } else {
          this.favorites.set(new Set(this.DEFAULT_FAVORITES));
      }
  }

  toggleFavorite(code: string) {
      this.favorites.update(set => {
          const newSet = new Set(set);
          if (newSet.has(code)) {
              newSet.delete(code);
          } else {
              newSet.add(code);
          }
          localStorage.setItem(this.FAV_STORAGE_KEY, JSON.stringify(Array.from(newSet)));
          return newSet;
      });
  }

  isFavorite(code: string): boolean {
      return this.favorites().has(code);
  }

  updateFilterState(updates: Partial<FilterState>) {
    this.filterState.update(state => ({ ...state, ...updates }));
  }

  resetFilterState() {
     this.filterState.set({
        searchTerm: '',
        showFilters: false,
        filterGolden: false,
        filterHighVolume: false,
        filterBreakDowntrend: false,
        filterBreakMA5: false,
        filterBreakMA20: false,
        filterTrend: 'ALL',
        filterIndustry: 'ALL',
        filterSuggestion: 'ALL',
        filterMinBuySignals: 0,
        filterMinSellSignals: 0,
        filterMinScale: 0,
        filterMinAge: 0,
        currentPage: 1,
        sortField: 'score',
        sortDirection: 'desc'
     });
  }

  setDataSource(source: DataSourceType) {
    if (this.dataSource() === source) return;
    this.dataSource.set(source);

    // If we have data, just reload history
    const current = this.etfData();
    if (current.length > 0) {
        this.loading.set(true);
        this.fetchHistories(current);
    } else {
        this.loadAllEtfs();
    }
  }

  // Helpers
  private getMarketCode(code: string): string {
    if (code.startsWith('5') || code.startsWith('6')) return '1';
    return '0';
  }

  private getTencentCode(code: string): string {
      return (code.startsWith('5') || code.startsWith('6') ? 'sh' : 'sz') + code;
  }

  private classifyETF(name: string): string {
    if (/(300|500|1000|2000|50|100|800|创业板|科创|恒生|纳指|标普|红利|MSCI|综指|成指|大湾区|双创|中证|A50|道琼斯|日经|德国|法国|英国|东南亚|沙特)/.test(name)) return '宽基/指数';
    if (/(芯片|半导体|计算机|电子|5G|人工智能|游戏|传媒|通信|软件|科技|互联|AI|数据|卫星|信创|机器人|云计算|元宇宙|智能|信息|机床)/.test(name)) return '科技/TMT';
    if (/(医疗|药|生物|疫苗|医|健康|基因|中药)/.test(name)) return '医药/生物';
    if (/(酒|食品|家电|消费|旅游|养殖|农|畜|文娱|教育|美妆|饮料|乳)/.test(name)) return '大消费';
    if (/(光伏|电池|新能源|碳中和|车|绿电|电力|储能|环保|低碳|光电)/.test(name)) return '新能源/车';
    if (/(银行|券商|证券|保险|金融|FinTech|央企股东回报)/i.test(name)) return '金融';
    if (/(黄金|豆粕|有色|金属|稀土|铝|铜|矿|油|石化|煤炭|钢铁|能源|化工|基建|地产|房地产|建材|材料)/.test(name)) return '周期/资源';
    if (/(军工|国防|航天)/.test(name)) return '军工';
    if (/(债|政金|国开|同业存单)/.test(name)) return '债券';
    if (/(货币|理财|现金)/.test(name)) return '货币';
    return '其他';
  }

  private parseRawNumber(val: any): number {
    if (val === undefined || val === null || val === '-') return 0;
    if (typeof val === 'number') return val;
    return parseFloat(val) || 0;
  }

  // --- Main Methods ---

  /**
   * Load All ETFs Logic
   * Primary List Source: Eastmoney (Most reliable for lists)
   * History Source: Configurable (Eastmoney / Tencent)
   */
  loadAllEtfs() {
    if (this.loading()) return;
    this.loading.set(true);
    this.error.set(null);

    // Always use Eastmoney for the base list as it provides real-time snapshot + name + cap in one go
    const url = 'https://push2.eastmoney.com/api/qt/clist/get?pn=1&pz=2000&po=1&np=1&ut=bd1d9ddb04089700cf9c27f6f7426281&fltt=2&invt=2&wbp2u=|0|0|0|web&fid=f3&fs=b:MK0021&fields=f12,f13,f14,f2,f3,f4,f5,f6,f20,f21';

    this.http.jsonp<any>(url, 'cb').pipe(
        retry(1), 
        timeout(10000),
        catchError(err => {
            console.warn('Primary List API (Eastmoney) failed, switching to Fallback...', err);
            return this.loadFallbackEtfs();
        })
    ).subscribe({
        next: (res: any) => {
            if (res && res.data && res.data.diff) {
                this.processEastmoneyList(res.data.diff);
            } else if (Array.isArray(res)) {
                this.etfData.set(res);
                this.fetchHistories(res);
            } else {
                this.loadFallbackEtfs().subscribe(fallbackData => {
                    this.etfData.set(fallbackData);
                    this.fetchHistories(fallbackData);
                });
            }
        },
        error: (err) => {
            console.error('Final Load Error:', err);
            this.loadFallbackEtfs().subscribe(fallbackData => {
                this.etfData.set(fallbackData);
                this.loading.set(false);
            });
        }
    });
  }

  private processEastmoneyList(diff: any) {
      const rawList = Array.isArray(diff) ? diff : Object.values(diff);
      const marketDataMap = new Map<string, any>();
      rawList.forEach((item: any) => marketDataMap.set(item.f12, item));

      const baseAnalysis: ETFAnalysis[] = ETF_LIST.map(def => {
          const raw = marketDataMap.get(def.code);
          const price = raw ? this.parseRawNumber(raw.f2) : 0;
          let marketCap = raw ? this.parseRawNumber(raw.f20) : 0; 
          if (marketCap <= 0 && raw) marketCap = this.parseRawNumber(raw.f21);

          return this.createEtfItem(def, price, raw ? this.parseRawNumber(raw.f3) : 0, marketCap);
      });

      const validList = baseAnalysis.filter(e => e.currentPrice > 0);
      const finalList = validList.length > 0 ? validList : baseAnalysis;

      this.etfData.set(finalList);
      this.fetchHistories(finalList);
  }

  private loadFallbackEtfs(): Observable<ETFAnalysis[]> {
      return of(ETF_LIST.map(def => this.createEtfItem(def, 0, 0, 0))); 
  }

  private createEtfItem(def: ETFDefinition, price: number, pct: number, cap: number): ETFAnalysis {
      return {
        ...def,
        currentPrice: price,
        changePercent7d: pct, 
        isGolden: false,
        breakMA5: false,
        breakMA20: false,
        breakDowntrend: false,
        isHighVolume: false,
        buySignals: 0,
        sellSignals: 0,
        buyFactors: [],
        sellFactors: [],
        trend: 'SIDEWAYS',
        score: 50,
        health: 50,
        suggestion: 'WAIT',
        lastUpdated: new Date().toLocaleTimeString(),
        history: [],
        fundSize: cap / 100000000, 
        establishmentDate: '-',
        age: 0,
        suggestedEntryPrice: 0,
        goldenPrice: 0,
        industry: def.industry || this.classifyETF(def.name)
    };
  }

  private fetchHistories(currentList: ETFAnalysis[]) {
     from(currentList).pipe(
        mergeMap(item => this.fetchSingleHistory(item, 120), 4), 
        toArray()
     ).subscribe({
        next: (updatedList) => {
            this.etfData.update(current => {
               const map = new Map(updatedList.map(u => [u.code, u]));
               return current.map(c => map.get(c.code) || c);
            });
            this.loading.set(false);
        },
        error: (err) => {
            console.error('History Fetch Error:', err);
            this.loading.set(false); 
        }
     });
  }

  // --- History Fetch Strategy ---

  private fetchSingleHistory(item: ETFAnalysis, limit: number): Observable<ETFAnalysis> {
     const source = this.dataSource();
     if (source === 'TENCENT') {
         return this.fetchHistoryTencent(item, limit).pipe(
             catchError(err => {
                 // Fallback to Eastmoney if Tencent fails
                 console.warn(`Tencent history failed for ${item.code}, switching to Eastmoney fallback.`);
                 return this.fetchHistoryEastmoney(item, limit);
             })
         );
     } else {
         return this.fetchHistoryEastmoney(item, limit);
     }
  }

  // 1. Eastmoney
  private fetchHistoryEastmoney(item: ETFAnalysis, limit: number): Observable<ETFAnalysis> {
     const secid = `${this.getMarketCode(item.code)}.${item.code}`;
     const urlPrimary = `https://push2his.eastmoney.com/api/qt/stock/kline/get?secid=${secid}&fields1=f1,f2,f3,f4,f5,f6&fields2=f51,f52,f53,f54,f55,f56,f57,f58,f59,f60,f61&klt=101&fqt=1&end=20500101&lmt=${limit}`;

     return this.http.jsonp<any>(urlPrimary, 'cb').pipe(
        retry(1),
        timeout(8000),
        map((res: any) => {
            if (res && res.data && res.data.klines) {
                const history = this.parseEastmoneyKlines(res.data.klines);
                return this.analyzeETF(item, history);
            }
            throw new Error('No data from Primary');
        }),
        catchError(err => {
            // Fallback to PDFM if Primary fails
            return this.fetchHistoryFromPdfm(item, limit);
        })
     );
  }

  private fetchHistoryFromPdfm(item: ETFAnalysis, limit: number): Observable<ETFAnalysis> {
      const suffix = item.code.startsWith('5') || item.code.startsWith('6') ? '1' : '2';
      const id = `${item.code}${suffix}`;
      const token = '4f1862fc3b5e77c150a2b985b12db0fd'; 
      const url = `https://pdfm.eastmoney.com/EM_UBG_PDTI_Fast/api/js?rtntype=5&token=${token}&type=k&authorityType=&id=${id}`;

      return this.http.jsonp<any>(url, 'cb').pipe(
          timeout(5000),
          map((res: any) => {
              if (res && res.data && Array.isArray(res.data)) {
                  const rawLines = res.data;
                  const sliced = rawLines.slice(-limit);
                  const history = this.parseEastmoneyKlines(sliced);
                  return this.analyzeETF(item, history);
              }
              return item;
          }),
          catchError(() => of(item))
      );
  }

  // 2. Tencent (Web Interface)
  private fetchHistoryTencent(item: ETFAnalysis, limit: number): Observable<ETFAnalysis> {
      // URL: http://web.ifzq.gtimg.cn/appstock/app/fqkline/get?param=sh510300,day,,,320,qfq
      const tCode = this.getTencentCode(item.code);
      const url = `https://web.ifzq.gtimg.cn/appstock/app/fqkline/get?param=${tCode},day,,,${limit},qfq`;

      // Tencent returns a JSON object via callback.
      return this.http.jsonp<any>(url, 'callback').pipe(
          timeout(8000),
          map((res: any) => {
              if (res && res.data && res.data[tCode] && res.data[tCode].day) {
                  const dayData = res.data[tCode].day;
                  // Tencent Format: ["2023-01-01", "open", "close", "high", "low", "vol", ...]
                  const history: KlinePoint[] = dayData.map((d: any[]) => ({
                      date: d[0],
                      open: parseFloat(d[1]),
                      close: parseFloat(d[2]),
                      high: parseFloat(d[3]),
                      low: parseFloat(d[4]),
                      volume: parseFloat(d[5]),
                      amount: parseFloat(d[5]) * parseFloat(d[2]) // Estimate Amount as Vol * Close
                  }));
                  return this.analyzeETF(item, history);
              }
              // Throw error to trigger catchError in fetchSingleHistory
              throw new Error('Invalid Tencent Data');
          })
      );
  }

