                                             </span>
                                          </td>
                                          <td class="p-2 text-right">{{ log.price | number:'1.3-3' }}</td>
                                          <td class="p-2 text-right">{{ log.shares }}</td>
                                          <td class="p-2 text-right">
                                             @if (log.pnlAmount) {
                                                <span [class.text-red-500]="log.pnlAmount > 0" [class.text-green-500]="log.pnlAmount < 0">
                                                   {{ log.pnlAmount > 0 ? '+' : ''}}{{ log.pnlAmount | number:'1.0-0' }}
                                                </span>
                                             } @else { <span class="text-gray-300">-</span> }
                                          </td>
                                          <td class="p-2 text-right">
                                             @if (log.pnlRatio) {
                                                <span [class.text-red-500]="log.pnlRatio > 0" [class.text-green-500]="log.pnlRatio < 0">
                                                   {{ log.pnlRatio | number:'1.2-2' }}%
                                                </span>
                                             } @else { <span class="text-gray-300">-</span> }
                                          </td>
                                          <td class="p-2 text-gray-500 text-[10px] break-words whitespace-normal" title="{{log.reason}}">{{ log.reason }}</td>
                                          <td class="p-2 text-right pr-6 font-bold text-slate-700">{{ (log.totalPosPercent * 100) | number:'1.0-0' }}%</td>
                                       </tr>
                                    }
                                 </tbody>
                              </table>
                           </div>
                        </div>
                     }
                </div>
            </div>
         </div>
       </div>
    }
  `,
  styles: [`
    .custom-scrollbar::-webkit-scrollbar { width: 4px; height: 4px; }
    .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
    .custom-scrollbar::-webkit-scrollbar-thumb { background: #cbd5e1; border-radius: 2px; }
  `]
})
export class DetailComponent implements OnInit {
  private route: ActivatedRoute = inject(ActivatedRoute);
  private etfService = inject(EtfService);
  private router = inject(Router);

  // ViewChilds
  chartContainer = viewChild<ElementRef>('chartContainer');
  strategyChartContainer = viewChild<ElementRef>('strategyChartContainer');

  code = signal<string>('');
  data = signal<ETFAnalysis | null>(null);

  // Moving Average Visibility Signals
  showMA5 = signal(true);
  showMA20 = signal(false);
  showMA60 = signal(false);

  // Overlay Visibility Signals
  showTrendChannel = signal(true);
  showFib = signal(true);
  // Grid and Chan removed as per request
  showSupRes = signal(false); 
  showVolume123 = signal(false);
  showResonance = signal(false); 
  showVolPrice = signal(false);
  showMASlope = signal(false);
  showStrategyMarkers = signal(false); // New Signal for R0-R10 Markers

  showDrawingsMenu = signal(false);

  ranges = [30, 60, 90, 120];
  selectedRange = signal<number>(60); 

  // --- Advanced Strategy State ---
  showStrategyModal = signal(false);
  isStrategyLoading = signal(false);
  strategyErrorMsg = signal<string | null>(null);

  strategyConfig: StrategyConfig = {
    etfCode: '', 
    startDate: '2020-01-01',
    endDate: new Date().toISOString().split('T')[0],
    initialCapital: 100000,
    commission: 0.0003,
    trendShortN: 10,
    trendLongM: 20,
    trendSlopeThreshold: 0.05, 
    fibCallback1: 0.328,
    fibCallback2: 0.618,
    fibExtension: 1.0,
    volBreakoutRatio: 1.5,
    volShrinkRatio: 0.6,
    posMode: 'PERCENT',
    posInitial: 30, 
    posAdd1: 0.3, 
    posAdd2: 0.7, 
    posMax: 80, 
    stopLossPct: 0.05,
    takeProfitPct: 0.30
  };

  strategyResult = signal<BacktestStats | null>(null);
  strategyLogs = signal<TradeLog[]>([]);
  strategyChartData = signal<{history: KlinePoint[], markers: any[], channels: ChannelPoint[]} | null>(null);

  resizeObserver: ResizeObserver | null = null;

  constructor() {
    effect(() => {
      const d = this.data();
      const container = this.chartContainer();

      // Trigger re-render on any signal change
      this.showMA5(); this.showMA20(); this.showMA60();
      // Grid removed
      this.showFib(); this.showTrendChannel(); this.showSupRes(); this.showVolume123();
      this.showResonance(); this.showVolPrice(); this.showMASlope();
      // Chan removed
      this.showStrategyMarkers();
      this.selectedRange();

      if (d && container) {
        setTimeout(() => this.renderChart(d, container), 0);
      }
    });

    // Effect for Strategy Chart
    effect(() => {
        const d = this.strategyChartData();
        const container = this.strategyChartContainer();
        if (this.showStrategyModal() && d && container) {
            setTimeout(() => this.renderStrategyChart(d, container), 0);
        }
    });

    // Resize Observer for Main Chart to handle mobile rotation
    effect(() => {
       const container = this.chartContainer();
       if (container) {
           if (this.resizeObserver) this.resizeObserver.disconnect();
           this.resizeObserver = new ResizeObserver(() => {
               const d = this.data();
               if(d) this.renderChart(d, container);
           });
           this.resizeObserver.observe(container.nativeElement);
       }
    });
  }

  ngOnInit() {
    this.route.paramMap.subscribe(params => {
      const c = params.get('code');
      if (c) {
        this.code.set(c);
        this.strategyConfig.etfCode = c;
        this.loadData(c);
      }
    });
  }

  ngOnDestroy() {
      if (this.resizeObserver) this.resizeObserver.disconnect();
  }

  loadData(code: string) {
    this.data.set(null);
    this.etfService.getEtfDetails(code).subscribe(res => {
      this.data.set(res);
    });
  }

  setRange(r: number) { this.selectedRange.set(r); }

  toggleMA(type: 'ma5' | 'ma20' | 'ma60') {
    if (type === 'ma5') this.showMA5.update(v => !v);
    if (type === 'ma20') this.showMA20.update(v => !v);
    if (type === 'ma60') this.showMA60.update(v => !v);
  }

  toggleDrawingsMenu() { this.showDrawingsMenu.update(v => !v); }
  toggleTrendChannel() { this.showTrendChannel.update(v => !v); }
  toggleFib() { this.showFib.update(v => !v); }
  toggleSupRes() { this.showSupRes.update(v => !v); }
  toggleVolume123() { this.showVolume123.update(v => !v); }
  toggleResonance() { this.showResonance.update(v => !v); }
  toggleVolPrice() { this.showVolPrice.update(v => !v); }
  toggleMASlope() { this.showMASlope.update(v => !v); }
  toggleStrategyMarkers() { this.showStrategyMarkers.update(v => !v); }

  // --- Strategy Methods ---
  openStrategy() {
      this.strategyConfig.etfCode = this.code();
      this.showStrategyModal.set(true);
      // Auto run if first open
      if (!this.strategyResult()) {
          this.runAdvancedStrategy();
      }
  }
  closeStrategy() { this.showStrategyModal.set(false); }

  resetStrategyConfig() {
      this.strategyConfig = {
        ...this.strategyConfig,
        trendShortN: 10, trendLongM: 20,
        fibCallback1: 0.328, fibCallback2: 0.618,
        volBreakoutRatio: 1.5, volShrinkRatio: 0.6,
        posMode: 'PERCENT', posInitial: 30, posAdd1: 0.3, posAdd2: 0.7, posMax: 80,
        stopLossPct: 0.05, takeProfitPct: 0.30
      };
  }

  runAdvancedStrategy() {
    if (!this.strategyConfig.etfCode) return;
    this.isStrategyLoading.set(true);
    this.strategyErrorMsg.set(null);
    this.strategyResult.set(null);

    this.etfService.getBacktestData(this.strategyConfig.etfCode).subscribe({
       next: (data) => {
          if (!data || data.history.length < 100) {
             this.strategyErrorMsg.set('数据不足，无法执行长周期回测');
             this.isStrategyLoading.set(false);
             return;
          }
          setTimeout(() => {
             this.executeAdvancedStrategy(data.history);
             this.isStrategyLoading.set(false);
          }, 100);
       },
       error: () => {
          this.strategyErrorMsg.set('数据获取失败');
          this.isStrategyLoading.set(false);
       }
    });
  }

  private executeAdvancedStrategy(fullHistory: KlinePoint[]) {
     const history = fullHistory.filter(d => d.date >= this.strategyConfig.startDate && d.date <= this.strategyConfig.endDate);
     if (history.length < 50) {
         this.strategyErrorMsg.set('选定区间内数据不足 (需要至少50天)');
         return;
     }

     let cash = this.strategyConfig.initialCapital;
     let shares = 0;
     let entryPrice = 0; 
     const tradeLogs: TradeLog[] = [];
     const markers: any[] = [];
     const equityCurve: {date: string, value: number}[] = [];
     const channels: ChannelPoint[] = [];

     let waveHigh = -Infinity;
     let waveLow = Infinity;
     let lastAction: TradeAction | 'NONE' = 'NONE';

     const M = this.strategyConfig.trendLongM;

     // Linear Regression Channel Helper
     const getSlopeAndChannel = (idx: number, period: number): {slope: number, top: number, bottom: number, middle: number} => {
         if (idx < period - 1) return { slope: 0, top: history[idx].high, bottom: history[idx].low, middle: history[idx].close };

         let sumX=0, sumY=0, sumXY=0, sumXX=0;
         const startIndex = idx - period + 1;

         for(let i=0; i<period; i++) {
             const p = history[startIndex + i];
             const x = i;
             const y = p.close;
             sumX += x; sumY += y; sumXY += x*y; sumXX += x*x;
         }

         const slope = (period * sumXY - sumX * sumY) / (period * sumXX - sumX * sumX);
         const intercept = (sumY - slope * sumX) / period;

         let maxDevHigh = -Infinity;
         let minDevLow = Infinity;

         for(let i=0; i<period; i++) {
             const p = history[startIndex + i];
             const regY = slope * i + intercept;
             maxDevHigh = Math.max(maxDevHigh, p.high - regY);
             minDevLow = Math.min(minDevLow, p.low - regY);
         }

         const currentX = period - 1;
         const currentMid = slope * currentX + intercept;

         return {
             slope: slope / history[idx].close, 
             middle: currentMid,
             top: currentMid + maxDevHigh,
             bottom: currentMid + minDevLow
         };
     };

     const buy = (idx: number, type: TradeAction, reason: string) => {
         const p = history[idx].close;
         let budget = 0;
         const totalAsset = cash + shares * p;

         if (type === '建') {
             if (this.strategyConfig.posMode === 'FIXED') budget = this.strategyConfig.posInitial;
             else budget = this.strategyConfig.initialCapital * (this.strategyConfig.posInitial / 100);
         } else if (type.includes('加')) {
             const initialBase = this.strategyConfig.posMode === 'FIXED' ? this.strategyConfig.posInitial : (this.strategyConfig.initialCapital * this.strategyConfig.posInitial/100);
             const multiplier = type === '加1' ? this.strategyConfig.posAdd1 : this.strategyConfig.posAdd2;
             budget = initialBase * multiplier;
         }

         const maxAsset = totalAsset * (this.strategyConfig.posMax / 100);
         const currentPosVal = shares * p;
         if (currentPosVal >= maxAsset) return; 

         budget = Math.min(budget, cash);
         budget = Math.min(budget, maxAsset - currentPosVal);

         const tradeShares = Math.floor(budget / p / 100) * 100;
         if (tradeShares <= 0) return;

         const cost = tradeShares * p;
         const fee = cost * this.strategyConfig.commission;

         if (cash < cost + fee) return;

         cash -= (cost + fee);
         entryPrice = (entryPrice * shares + cost) / (shares + tradeShares);
         shares += tradeShares;

         tradeLogs.push({
             date: history[idx].date, action: type, price: p, shares: tradeShares, amount: cost, reason,
             totalPosPercent: (shares*p)/(cash + shares*p)
         });
         markers.push({date: history[idx].date, type: 'BUY', label: type, price: p, reason: reason});
         lastAction = type;

         if (type === '建') {
             waveHigh = p; 
             waveLow = history.slice(Math.max(0, idx-30), idx).reduce((min, cur) => Math.min(min, cur.low), Infinity);
         }
     };

     const sell = (idx: number, type: TradeAction, reason: string, ratio: number = 1.0) => {
         if (shares === 0) return;
         const p = history[idx].close;
         const actualShares = Math.min(shares, Math.max(100, Math.floor(shares * ratio / 100) * 100));

         if (actualShares <= 0) return;

         const revenue = actualShares * p;
         const fee = revenue * this.strategyConfig.commission;
         const cost = actualShares * entryPrice;
         const pnl = revenue - fee - cost;

         cash += (revenue - fee);
         shares -= actualShares;
         if (shares < 100) { 
             const dustRev = shares * p;
             cash += dustRev;
             shares = 0;
         }

         tradeLogs.push({
             date: history[idx].date, action: type, price: p, shares: actualShares, amount: revenue, reason,
             pnlAmount: pnl, pnlRatio: (p - entryPrice)/entryPrice * 100,
             totalPosPercent: (shares*p)/(cash + shares*p)
         });
         markers.push({date: history[idx].date, type: 'SELL', label: type, price: p, reason: reason});
         lastAction = type;

         if (shares === 0) {
             lastAction = 'NONE';
             waveHigh = -Infinity;
         }
     };

     for (let i = M; i < history.length; i++) {
         const today = history[i];

         if (shares > 0) {
             if (today.high > waveHigh) waveHigh = today.high;
         }

         const channelInfo = getSlopeAndChannel(i, this.strategyConfig.trendLongM);
         channels.push({ date: today.date, ...channelInfo });

         const slopeShort = getSlopeAndChannel(i, this.strategyConfig.trendShortN).slope;
         const volAvg = history.slice(i-5, i).reduce((a,b)=>a+b.volume,0)/5;
         const volRatio = today.volume / (volAvg || 1);

         // 1. ENTRY
         if (shares === 0) {
             const recentHigh = Math.max(...history.slice(i-this.strategyConfig.trendShortN, i).map(d => d.high));
             if (today.close > recentHigh && channelInfo.slope > 0 && volRatio > this.strategyConfig.volBreakoutRatio) {
                 buy(i, '建', '突破新高+放量');
             }
         } 
         // 2. HOLDING
         else {
             const range = waveHigh - waveLow;
             const fib1 = waveHigh - range * this.strategyConfig.fibCallback1; 
             const fib2 = waveHigh - range * this.strategyConfig.fibCallback2; 

             // A. STOP LOSS
             if (today.close < entryPrice * (1 - this.strategyConfig.stopLossPct)) {
                 sell(i, '止损', '硬损触发');
                 continue;
             }
             if (range > 0 && today.close < waveHigh - range * 1.2) { 
                 sell(i, '清仓', '趋势破坏');
                 continue;
             }

             // B. ADD POSITIONS
             if (volRatio < this.strategyConfig.volShrinkRatio) {
                 if (today.low <= fib1 && today.close > fib1 * 0.98 && (lastAction as string) === '建') {
                     buy(i, '加1', '回调Fib1+缩量');
                 } else if (today.low <= fib2 && today.close > fib2 * 0.98 && ((lastAction as string) === '建' || (lastAction as string) === '加1')) {
                     buy(i, '加2', '回调Fib2+缩量');
                 }
             }

             // C. TAKE PROFIT
             if ((today.close - entryPrice) / entryPrice > this.strategyConfig.takeProfitPct) {
                 sell(i, '止盈2', '达到硬性止盈位');
                 continue;
             }
             const extPrice = waveHigh + range * this.strategyConfig.fibExtension;
             if (today.high >= extPrice) {
                 sell(i, '止盈1', '触及延伸目标位', 50); 
             }

             if (slopeShort < -0.02) { 
                 sell(i, '清仓', '短期趋势反转');
             }
         }

         equityCurve.push({date: today.date, value: cash + shares * today.close});
     }

     const finalBal = equityCurve[equityCurve.length-1].value;
     let peak = this.strategyConfig.initialCapital;
     let maxDd = 0;
     equityCurve.forEach(e => {
         if (e.value > peak) peak = e.value;
         const dd = (peak - e.value) / peak;
         if (dd > maxDd) maxDd = dd;
     });

     const totalTrades = tradeLogs.filter(t => t.pnlAmount !== undefined).length;
     const winningTrades = tradeLogs.filter(t => t.pnlAmount && t.pnlAmount > 0).length;

     this.strategyLogs.set(tradeLogs.reverse());
     this.strategyChartData.set({ history, markers, channels });
     this.strategyResult.set({
         finalBalance: finalBal,
         totalReturn: (finalBal - this.strategyConfig.initialCapital) / this.strategyConfig.initialCapital * 100,
         maxDrawdown: maxDd * 100,
         winRate: totalTrades > 0 ? (winningTrades / totalTrades) * 100 : 0,
         tradeCount: totalTrades,
         avgHoldDays: totalTrades > 0 ? Math.floor(history.length / totalTrades / 2) : 0, // Approx
         equityCurve,
         marketTypeStats: { bull: {wins:0,total:0}, bear: {wins:0,total:0}, sideways: {wins:0,total:0} }
     });
  }

  // --- Helpers for Template ---

  avgVolatility30d = computed(() => {
    const hist = this.data()?.history || [];
    if (hist.length < 30) return 0;
    const recent = hist.slice(-30);
    const sum = recent.reduce((acc, curr) => acc + (curr.high - curr.low) / curr.low, 0);
    return (sum / recent.length) * 100;
  });

  recentHistory = computed(() => {
    return this.data()?.history.slice(-30) || [];
  });

  fibLevels = computed<FibLevel[]>(() => {
    const d = this.data();
    if (!d || !d.history.length) return [];

    const range = this.selectedRange();
    const hist = d.history.slice(-range);
    const high = Math.max(...hist.map(k => k.high));
    const low = Math.min(...hist.map(k => k.low));
    const diff = high - low;

    const levels: FibLevel[] = [];

    if (d.trend === 'DOWN') {
        levels.push({ val: low, label: '0% (低点)', color: '#22c55e', dash: 'solid', isBase: true });
        levels.push({ val: high, label: '100% (高点)', color: '#ef4444', dash: 'solid' });
        levels.push({ val: low + diff * 0.382, label: '38.2% 压力', color: '#f97316', dash: '5,3' });
        levels.push({ val: low + diff * 0.5, label: '50.0% 中枢', color: '#94a3b8', dash: '3,3' });
        levels.push({ val: low + diff * 0.618, label: '61.8% 强压', color: '#ef4444', dash: '5,3' });
        levels.push({ val: low - diff * 0.382, label: '138.2% 拓展', color: '#22c55e', dash: '2,2', isExtension: true });
    } else {
        levels.push({ val: high, label: '0% (高点)', color: '#ef4444', dash: 'solid', isBase: true });
        levels.push({ val: low, label: '100% (低点)', color: '#22c55e', dash: 'solid' });
        levels.push({ val: high - diff * 0.382, label: '38.2% 支撑', color: '#f97316', dash: '5,3' });
        levels.push({ val: high - diff * 0.5, label: '50.0% 中枢', color: '#94a3b8', dash: '3,3' });
        levels.push({ val: high - diff * 0.618, label: '61.8% 强撑', color: '#22c55e', dash: '5,3' });
        levels.push({ val: high + diff * 0.382, label: '138.2% 拓展', color: '#ef4444', dash: '2,2', isExtension: true });
    }

    return levels;
  });

  getVolatilityPercent(point: KlinePoint): number {
      const hist = this.recentHistory();
      if (!hist.length) return 0;
      const maxAmp = Math.max(...hist.map(p => (p.high - p.low)/p.low));
      const currentAmp = (point.high - point.low) / point.low;
      return maxAmp > 0 ? (currentAmp / maxAmp) * 100 : 0;
  }

  translateSuggestion(s: string | undefined): string {
    if (!s) return '';
    const map: Record<string, string> = {
      'OBSERVE': '👁 观察点',
      'BUY_POINT': '🚩 建仓点',
      'HOLD': '✊ 持仓待涨',
      'TAKE_PROFIT_REDUCE': '🎯 止盈A',
      'TAKE_PROFIT_CLEAR': '💰 止盈B',
      'STOP_LOSS_REDUCE': '🛡 止损A',
      'STOP_LOSS_CLEAR': '❌ 清仓点',
      'WAIT': '⏳ 观望'
    };
    return map[s] || s;
  }

  // --- Chart Rendering ---

  renderChart(data: ETFAnalysis, containerRef: ElementRef) {
    if (!data.history || data.history.length === 0) return;
    try {
        const element = containerRef.nativeElement;
        d3.select(element).selectAll('*').remove();

        const range = this.selectedRange();
        const history = data.history.slice(-range);

        const margin = { top: 20, right: 50, bottom: 30, left: 10 };
        const width = element.clientWidth - margin.left - margin.right;
        const height = element.clientHeight - margin.top - margin.bottom;

        const mainH = height * 0.65;
        const volH = height * 0.15;
        const macdH = height * 0.15;
        const gap = height * 0.025;

        const svg = d3.select(element).append('svg')
          .attr('width', width + margin.left + margin.right)
          .attr('height', height + margin.top + margin.bottom)
          .append('g')
          .attr('transform', `translate(${margin.left},${margin.top})`);

        const x = d3.scaleBand()
          .domain(history.map(d => d.date))
          .range([0, width])
          .padding(0.2);

        // Initial Y Domain from Data
        let yMin = d3.min(history, d => d.low)! * 0.98;
        let yMax = d3.max(history, d => d.high)! * 1.02;

        // Expand Domain for Fib Extensions
        if (this.showFib()) {
           const fibs = this.fibLevels();
           if (fibs.length > 0) {
               const minFib = Math.min(...fibs.map(f => f.val));
               const maxFib = Math.max(...fibs.map(f => f.val));
               yMin = Math.min(yMin, minFib * 0.99); // Expand down if needed
               yMax = Math.max(yMax, maxFib * 1.01); // Expand up if needed
           }
        }

        const y = d3.scaleLinear().domain([yMin, yMax]).range([mainH, 0]);

        const volMax = d3.max(history, d => d.volume)!;
        const yVol = d3.scaleLinear().domain([0, volMax]).range([mainH + volH + gap, mainH + gap]);

        const macdVals = history.flatMap(d => [d.macd?.diff || 0, d.macd?.dea || 0, d.macd?.macd || 0]);
        const macdLimit = Math.max(Math.abs(d3.min(macdVals) || 0), Math.abs(d3.max(macdVals) || 0));
        const macdTop = mainH + volH + 2 * gap;
        const yMacd = d3.scaleLinear().domain([-macdLimit, macdLimit]).range([height, macdTop]);

        // Axis
        const xAxis = d3.axisBottom(x)
           .tickValues(x.domain().filter((d, i) => i % Math.floor(history.length / 5) === 0))
           .tickFormat(d => d.slice(5)); 

        svg.append('g').attr('transform', `translate(0,${height})`).call(xAxis).attr('class', 'text-gray-400 text-[10px]');
        svg.append('g').attr('transform', `translate(${width},0)`).call(d3.axisRight(y).ticks(5)).attr('class', 'text-gray-400 text-[10px]');

        // Layers
        if (this.showTrendChannel()) drawTrendChannel(svg, history, x, y, width);

        if (this.showFib()) {
           const fibs = this.fibLevels(); // Recalculate based on current computed
           drawFibonacci(svg, fibs, width, y, 0, mainH); // Pass mainH instead of height for correct scaling
        }

        drawBaseLayer(svg, history, x, y, width, {
            showGrid: false, // Removed Grid Toggle
            showMA5: this.showMA5(),
            showMA20: this.showMA20(),
            showMA60: this.showMA60()
        });

        if (this.showSupRes()) drawSupRes(svg, history, x, y, width, svg);
        if (this.showVolume123()) drawVolumeProfile(svg, history, x, y, width);
        if (this.showResonance() && data.boxSignal) drawResonanceSignal(svg, data.boxSignal, x, y, width);
        if (this.showVolPrice()) drawVolPriceMomentum(svg, history, x, y, width);
        if (this.showMASlope()) drawMASlope(svg, history, x, y);
        // Chan structure removed
        if (this.showStrategyMarkers()) drawStrategyMarkers(svg, history, x, y, width);

        const volGroup = svg.append('g');
        const macdGroup = svg.append('g');
        drawSubCharts(volGroup, macdGroup, history, x, yVol, yMacd, mainH + volH + gap, height - macdTop, width, macdTop);

        // Crosshair
        const tooltip = d3.select(element).append('div')
             .attr('class', 'chart-tooltip')
             .style('display', 'none')
             .style('pointer-events', 'none')
             .style('position', 'absolute')
             .style('z-index', '20')
             .style('background', 'rgba(255,255,255,0.95)')
             .style('padding', '8px')
             .style('border', '1px solid #e2e8f0')
             .style('border-radius', '4px')
             .style('box-shadow', '0 4px 6px -1px rgba(0, 0, 0, 0.1)')
             .style('font-size', '10px');

        const crosshairX = svg.append('line').attr('stroke', '#94a3b8').attr('stroke-width', 1).attr('stroke-dasharray', '3,3').style('display', 'none').style('pointer-events', 'none');
        const crosshairY = svg.append('line').attr('stroke', '#94a3b8').attr('stroke-width', 1).attr('stroke-dasharray', '3,3').style('display', 'none').style('pointer-events', 'none');

        svg.append('rect')
           .attr('width', width).attr('height', height)
           .attr('fill', 'transparent')
           .style('cursor', 'crosshair')
           .on('mousemove', (event) => {
               const [mx, my] = d3.pointer(event);
               const step = x.step();
               const index = Math.floor(mx / step);
               if (index >= 0 && index < history.length) {
                   const d = history[index];
                   const xPos = x(d.date)! + x.bandwidth()/2;

                   crosshairX.attr('x1', xPos).attr('x2', xPos).attr('y1', 0).attr('y2', height).style('display', null);
                   crosshairY.attr('x1', 0).attr('x2', width).attr('y1', my).attr('y2', my).style('display', null);

                   let html = `<div class="font-bold mb-1">${d.date}</div>`;
                   html += `<div class="flex justify-between gap-4"><span>收盘:</span><span>${d.close.toFixed(3)}</span></div>`;
                   html += `<div class="flex justify-between gap-4"><span>涨跌:</span><span class="${d.close>d.open?'text-red-500':'text-green-500'}">${((d.close-d.open)/d.open*100).toFixed(2)}%</span></div>`;
                   html += `<div class="flex justify-between gap-4"><span>成交:</span><span>${(d.volume/10000).toFixed(0)}万</span></div>`;

                   const box = element.getBoundingClientRect();
                   let left = mx + 20;
                   let top = my + 20;
                   if (left + 150 > width) left = mx - 140;

                   tooltip.html(html)
                     .style('display', 'block')
                     .style('left', `${left}px`)
                     .style('top', `${top}px`);
               } else {
                   crosshairX.style('display', 'none');
                   crosshairY.style('display', 'none');
                   tooltip.style('display', 'none');
               }
           })
           .on('mouseleave', () => {
               crosshairX.style('display', 'none');
               crosshairY.style('display', 'none');
               tooltip.style('display', 'none');
           });
    } catch (e) {
        console.warn('D3 Chart Render Error:', e);
    }
  }

  private renderStrategyChart(data: {history: KlinePoint[], markers: any[], channels: ChannelPoint[]}, containerRef: ElementRef) {
     if (!data.history.length) return;
     try {
         const element = containerRef.nativeElement;
         d3.select(element).selectAll('*').remove();

         const { history, markers, channels } = data;

         const margin = { top: 20, right: 40, bottom: 20, left: 10 };
         const width = element.clientWidth - margin.left - margin.right;
         const height = element.clientHeight - margin.top - margin.bottom;

         const svg = d3.select(element).append('svg')
            .attr('width', width + margin.left + margin.right)
            .attr('height', height + margin.top + margin.bottom)
            .append('g')
            .attr('transform', `translate(${margin.left},${margin.top})`);

         const x = d3.scaleBand().domain(history.map(d => d.date)).range([0, width]).padding(0.2);
         const yMin = d3.min(history, d => d.low)! * 0.95;
         const yMax = d3.max(history, d => d.high)! * 1.05;
         const y = d3.scaleLinear().domain([yMin, yMax]).range([height, 0]);

         const xAxis = d3.axisBottom(x)
            .tickValues(x.domain().filter((d, i) => i % Math.floor(history.length / 5) === 0))
            .tickFormat(d => d.slice(2)); 

         svg.append('g').attr('transform', `translate(0,${height})`).call(xAxis).attr('class', 'text-gray-400 text-[9px]');
         svg.append('g').attr('transform', `translate(${width},0)`).call(d3.axisRight(y).ticks(5)).attr('class', 'text-gray-400 text-[9px]');

         // Trend Channels
         const channelSegments: { type: 'UP'|'DOWN', points: ChannelPoint[] }[] = [];
         let currentSegment: { type: 'UP'|'DOWN', points: ChannelPoint[] } | null = null;

         channels.forEach(pt => {
             const type = pt.slope >= 0 ? 'UP' : 'DOWN';
             if (!currentSegment || currentSegment.type !== type) {
                 if (currentSegment) channelSegments.push(currentSegment);
                 currentSegment = { type, points: [pt] };
             } else {
                 currentSegment.points.push(pt);
             }
         });
         if (currentSegment) channelSegments.push(currentSegment);

         const areaGen = d3.area().x((d: any) => x(d.date)! + x.bandwidth()/2).y0((d: any) => y(d.bottom)).y1((d: any) => y(d.top)).curve(d3.curveMonotoneX);
         const lineTop = d3.line().x((d: any) => x(d.date)! + x.bandwidth()/2).y((d: any) => y(d.top)).curve(d3.curveMonotoneX);
         const lineBottom = d3.line().x((d: any) => x(d.date)! + x.bandwidth()/2).y((d: any) => y(d.bottom)).curve(d3.curveMonotoneX);

         channelSegments.forEach(seg => {
             svg.append('path').datum(seg.points).attr('fill', seg.type === 'UP' ? '#fecaca' : '#bbf7d0').attr('fill-opacity', 0.4).attr('d', areaGen);
             const borderColor = seg.type === 'UP' ? '#ef4444' : '#22c55e';
             svg.append('path').datum(seg.points).attr('fill', 'none').attr('stroke', borderColor).attr('stroke-width', 1).attr('stroke-dasharray', '2,2').attr('d', lineTop);
             svg.append('path').datum(seg.points).attr('fill', 'none').attr('stroke', borderColor).attr('stroke-width', 1).attr('stroke-dasharray', '2,2').attr('d', lineBottom);
         });

         // Candles
         const candles = svg.selectAll('.candle').data(history).enter().append('g');
         candles.append('line').attr('x1', d => x(d.date)! + x.bandwidth()/2).attr('x2', d => x(d.date)! + x.bandwidth()/2).attr('y1', d => y(d.high)).attr('y2', d => y(d.low)).attr('stroke', d => d.close > d.open ? '#ef4444' : '#22c55e');
         candles.append('rect').attr('x', d => x(d.date)!).attr('y', d => y(Math.max(d.open, d.close))).attr('width', x.bandwidth()).attr('height', d => Math.max(1, Math.abs(y(d.open) - y(d.close)))).attr('fill', d => d.close > d.open ? '#ef4444' : '#22c55e');

         // Markers
         markers.forEach(m => {
             const mx = x(m.date);
             if (mx === undefined) return;
             const cx = mx + x.bandwidth()/2;
             const cy = y(m.price);
             const isBuy = m.type === 'BUY';
             const color = isBuy ? '#10b981' : (m.label.includes('止盈') ? '#f97316' : '#3b82f6');
             svg.append('circle').attr('cx', cx).attr('cy', isBuy ? cy + 10 : cy - 10).attr('r', 3).attr('fill', color);
             svg.append('text').attr('x', cx).attr('y', isBuy ? cy + 20 : cy - 12).text(m.label).attr('fill', color).attr('font-size', '8px').attr('text-anchor', 'middle').attr('font-weight', 'bold');
         });

         // Tooltip
         const tooltip = d3.select(element).append('div').attr('class', 'chart-tooltip').style('display', 'none').style('pointer-events', 'none').style('position', 'absolute').style('z-index', '20').style('background', 'rgba(255,255,255,0.95)').style('padding', '6px').style('border', '1px solid #e2e8f0').style('border-radius', '4px').style('box-shadow', '0 4px 6px -1px rgba(0, 0, 0, 0.1)').style('font-size', '10px');
         const crosshairX = svg.append('line').attr('stroke', '#94a3b8').attr('stroke-width', 1).attr('stroke-dasharray', '3,3').style('display', 'none').style('pointer-events', 'none');
         const crosshairY = svg.append('line').attr('stroke', '#94a3b8').attr('stroke-width', 1).attr('stroke-dasharray', '3,3').style('display', 'none').style('pointer-events', 'none');

         svg.append('rect').attr('width', width).attr('height', height).attr('fill', 'transparent').style('cursor', 'crosshair')
           .on('mousemove', (event) => {
               const [mx, my] = d3.pointer(event);
               const step = x.step();
               const index = Math.floor(mx / step);
               if (index >= 0 && index < history.length) {
                   const d = history[index];
                   const xPos = x(d.date)! + x.bandwidth()/2;

                   crosshairX.attr('x1', xPos).attr('x2', xPos).attr('y1', 0).attr('y2', height).style('display', null);
                   crosshairY.attr('x1', 0).attr('x2', width).attr('y1', my).attr('y2', my).style('display', null);

                   const m = markers.find(mark => mark.date === d.date);

                   let html = `<div class="font-bold mb-1">${d.date}</div>`;
                   html += `<div class="flex justify-between gap-4"><span>收盘:</span><span>${d.close.toFixed(3)}</span></div>`;

                   if (m) {
                       html += `<div class="mt-2 pt-1 border-t border-gray-200 font-bold ${m.type==='BUY'?'text-red-600':'text-green-600'}">${m.label}</div>`;
                       if (m.reason) html += `<div class="text-gray-500 max-w-[150px] whitespace-normal">${m.reason}</div>`;
                   }

                   let left = mx + 20;
                   let top = my + 20;
                   if (left + 150 > width) left = mx - 140;

                   tooltip.html(html)
                     .style('display', 'block')
                     .style('left', `${left}px`)
                     .style('top', `${top}px`);
               } else {
                   crosshairX.style('display', 'none');
                   crosshairY.style('display', 'none');
                   tooltip.style('display', 'none');
               }
           })
           .on('mouseleave', () => {
               crosshairX.style('display', 'none');
               crosshairY.style('display', 'none');
               tooltip.style('display', 'none');
           });
     } catch (e) {
         console.warn('D3 Strategy Render Error:', e);
     }
  }
}

import { Component, ElementRef, ViewChild, inject, signal, effect, computed, viewChild } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { EtfService, KlinePoint, ETFAnalysis } from '../../services/etf.service';
import * as d3Raw from 'd3';

const d3 = (d3Raw as any).default ?? d3Raw;

// ----------------------
// Interfaces & Types
// ----------------------

type TradeAction = '建' | '加1' | '加2' | '止盈1' | '止盈2' | '止损' | '清仓' | '观察';

interface TradeLog {
  date: string;
  action: TradeAction;
  price: number;
  shares: number;
  amount: number;
  reason: string;
  pnlRatio?: number; 
  pnlAmount?: number;
  totalPosPercent: number; 
}

interface ChannelPoint {
  date: string;
  middle: number;
  top: number;
  bottom: number;
  slope: number;
}

interface BacktestStats {
  finalBalance: number;
  totalReturn: number;
  maxDrawdown: number;
  winRate: number;
  tradeCount: number;
  avgHoldDays: number;
  equityCurve: { date: string, value: number }[];
  marketTypeStats: {
     bull: { wins: number, total: number };
     bear: { wins: number, total: number };
     sideways: { wins: number, total: number };
  };
}

interface StrategyConfig {
  // 1. Time & Target
  etfCode: string;
  startDate: string;
  endDate: string;
  initialCapital: number;
  commission: number; 

  // 2. Parallel Trend
  trendShortN: number; 
  trendLongM: number; 
  trendSlopeThreshold: number; 

  // 3. Golden Fib
  fibCallback1: number; 
  fibCallback2: number; 
  fibExtension: number; 

  // 4. Volume
  volBreakoutRatio: number; 
  volShrinkRatio: number; 

  // 5. Position
  posMode: 'PERCENT' | 'FIXED';
  posInitial: number; 
  posAdd1: number; 
  posAdd2: number; 
  posMax: number; 

  // 6. Stop/Profit
  stopLossPct: number; 
  takeProfitPct: number; 
}

interface FibLevel {
  val: number;
  label: string;
  color: string;
  dash: string;
  isExtension?: boolean;
  isBase?: boolean;
  bgClass?: string;
  textClass?: string;
  borderClass?: string;
}

@Component({
  selector: 'app-retracement',
  standalone: true,
  imports: [CommonModule, FormsModule],
  template: `
    <div class="flex flex-col lg:flex-row h-[calc(100vh-80px)] gap-4 animate-[fadeIn_0.3s_ease-out] overflow-hidden">

      <!-- Left Panel: Configuration -->
      <div class="w-full lg:w-80 flex-shrink-0 bg-white border-r border-gray-200 overflow-y-auto custom-scrollbar p-4 flex flex-col gap-5 shadow-sm z-10">
        <h2 class="text-lg font-bold text-slate-800 flex items-center justify-between sticky top-0 bg-white py-2 z-10 border-b border-gray-100">
          <span class="flex items-center gap-2"><i class="fa-solid fa-sliders text-indigo-600"></i> 策略配置</span>
          <button (click)="showRulesModal.set(true)" class="text-xs font-normal text-slate-500 hover:text-indigo-600 transition-colors flex items-center gap-1">
             <i class="fa-regular fa-circle-question"></i> 规则说明
          </button>
        </h2>

        <!-- Group 1: Basic -->
        <div class="space-y-3">
           <div class="text-[10px] font-bold text-gray-400 uppercase tracking-wider flex justify-between">
              <span>基础设置</span>
              <span class="text-indigo-500 cursor-pointer" (click)="resetConfig()">重置</span>
