// --- 4. Volume Profile + 123 Painter ---
export function drawVolumeProfile(
    container: SelectionGroup,
    data: KlinePoint[],
    x: ScaleBand,
    y: ScaleLinear,
    width: number
) {
    const yMin = y.domain()[0];
    const yMax = y.domain()[1];
    const binCount = 50;
    const binSize = (yMax - yMin) / binCount;
    const bins = new Array(binCount).fill(0);
    let maxVolBin = 0;
    let maxVolIdx = 0;

    data.forEach(d => {
        const idx = Math.floor((d.close - yMin) / binSize);
        if (idx >= 0 && idx < binCount) {
            bins[idx] += d.volume;
            if (bins[idx] > maxVolBin) {
                maxVolBin = bins[idx];
                maxVolIdx = idx;
            }
        }
    });

    const pocPrice = yMin + (maxVolIdx + 0.5) * binSize;
    const maxBarWidth = width * 0.2; 
    const vpGroup = container.append('g').attr('transform', `translate(${width}, 0)`);

    bins.forEach((vol, i) => {
        const barW = (vol / maxVolBin) * maxBarWidth;
        const barY = y(yMin + (i+1)*binSize);
        const barH = Math.abs(y(yMin + i*binSize) - barY);

        vpGroup.append('rect')
            .attr('x', -barW)
            .attr('y', barY)
            .attr('width', barW)
            .attr('height', barH)
            .attr('fill', i === maxVolIdx ? '#eab308' : '#64748b') 
            .attr('opacity', i === maxVolIdx ? 0.4 : 0.1);
    });

    container.append('line')
        .attr('x1', 0).attr('x2', width)
        .attr('y1', y(pocPrice)).attr('y2', y(pocPrice))
        .attr('stroke', '#eab308').attr('stroke-width', 1.5).attr('stroke-dasharray', '4,2');

    container.append('text')
        .attr('x', width - 5).attr('y', y(pocPrice) - 4)
        .text('POC (筹码峰)').attr('fill', '#eab308')
        .attr('font-size', '10px').attr('font-weight', 'bold').attr('text-anchor', 'end');

    // ZigZag / Wave Theory
    const zigzag: {x: number, y: number, date: string, type: 'HIGH'|'LOW'}[] = [];
    const lookback = Math.max(3, Math.floor(data.length / 20));

    for(let i=lookback; i<data.length-lookback; i++) {
            const d = data[i];
            const range = data.slice(i-lookback, i+lookback+1);
            const isHigh = range.every(item => item.high <= d.high);
            const isLow = range.every(item => item.low >= d.low);

            if (isHigh) zigzag.push({x: i, y: d.high, date: d.date, type: 'HIGH'});
            else if (isLow) zigzag.push({x: i, y: d.low, date: d.date, type: 'LOW'});
    }

    const cleanZigzag: typeof zigzag = [];
    zigzag.forEach(p => {
        if (cleanZigzag.length === 0) { cleanZigzag.push(p); return; }
        const last = cleanZigzag[cleanZigzag.length-1];
        if (last.type !== p.type) {
            cleanZigzag.push(p);
        } else {
            if (p.type === 'HIGH' && p.y > last.y) cleanZigzag[cleanZigzag.length-1] = p;
            if (p.type === 'LOW' && p.y < last.y) cleanZigzag[cleanZigzag.length-1] = p;
        }
    });

    const lineGen = d3.line()
        .x((d: any) => x(d.date)! + x.bandwidth()/2)
        .y((d: any) => y(d.y));

    // Draw Thin Black Lines for Segments
    container.append('path')
        .datum(cleanZigzag)
        .attr('fill', 'none')
        .attr('stroke', '#000000') 
        .attr('stroke-width', 1)
        .attr('opacity', 0.8)
        .attr('d', (d) => lineGen(d.map(p => ({x: p.x, y: p.y, date: p.date}))));

    // Draw Wave Labels (1, 2, 3, 4, 5, A, B, C)
    const waveLabels = ['1', '2', '3', '4', '5', 'A', 'B', 'C'];

    if (cleanZigzag.length > 0) {
        cleanZigzag.forEach((p, idx) => {
            const px = x(p.date)! + x.bandwidth()/2;
            const py = y(p.y);
            const label = waveLabels[idx % waveLabels.length];

            // Offset logic: HIGH above candle, LOW below candle
            const yOffset = p.type === 'HIGH' ? -15 : 15;

            const g = container.append('g').attr('transform', `translate(${px}, ${py + yOffset})`);

            // Purple Hollow Circle
            g.append('circle')
                .attr('r', 7)
                .attr('fill', 'white')
                .attr('stroke', '#a855f7') // Purple
                .attr('stroke-width', 1.5);

            // Text inside circle
            g.append('text')
                .text(label)
                .attr('dy', '0.35em')
                .attr('text-anchor', 'middle')
                .attr('fill', '#a855f7')
                .attr('font-size', '9px')
                .attr('font-weight', 'bold');
        });
    }
}

// --- 5. Resonance Signal Painter (Box Strategy) ---
export function drawResonanceSignal(
    container: SelectionGroup,
    signal: BoxSignal,
    x: ScaleBand,
    y: ScaleLinear,
    width: number
) {
    if (!signal || !signal.valid) return;

    const boxStartX = x(signal.boxStartDate);
    const obsX = x(signal.obsDate);
    const entryX = x(signal.date);
    const yHigh = y(signal.boxHigh);
    const yLow = y(signal.boxLow);
    const yPoc = y(signal.poc);
    const lineStart = boxStartX !== undefined ? boxStartX : (entryX !== undefined ? 0 : 0);

    if (entryX !== undefined || (boxStartX !== undefined)) {
            container.append('line').attr('x1', lineStart).attr('x2', width).attr('y1', yLow).attr('y2', yLow).attr('stroke', '#334155').attr('stroke-width', 2).attr('stroke-opacity', 0.8);
            container.append('line').attr('x1', lineStart).attr('x2', width).attr('y1', yHigh).attr('y2', yHigh).attr('stroke', '#334155').attr('stroke-width', 2).attr('stroke-opacity', 0.8);
            container.append('line').attr('x1', lineStart).attr('x2', width).attr('y1', yPoc).attr('y2', yPoc).attr('stroke', '#f97316').attr('stroke-width', 1).attr('stroke-dasharray', '4,2');
            if (boxStartX !== undefined) {
            container.append('text').attr('x', boxStartX + 5).attr('y', yPoc - 3).text('POC').attr('fill', '#f97316').attr('font-size', '10px');
            }
    }
    if (obsX !== undefined) {
            container.append('text').attr('x', obsX + x.bandwidth()/2).attr('y', yHigh - 10).text('👁').attr('font-size', '14px').attr('text-anchor', 'middle');
    }
    if (entryX !== undefined) {
        const cx = entryX + x.bandwidth()/2;
        const yEntry = y(signal.entryPrice);
        container.append('text').attr('x', cx).attr('y', yEntry + 15).text('🚩').attr('font-size', '14px').attr('text-anchor', 'middle');
        container.append('text').attr('x', cx).attr('y', yEntry + 28).text('建仓').attr('fill', '#ef4444').attr('font-size', '10px').attr('text-anchor', 'middle').attr('font-weight', 'bold');
    }

    const drawTarget = (val: number, label: string, color: string, icon: string) => {
        const yPos = y(val);
        container.append('line').attr('x1', 0).attr('x2', width).attr('y1', yPos).attr('y2', yPos).attr('stroke', color).attr('stroke-width', 1).attr('opacity', 0.8); 
        container.append('text').attr('x', 5).attr('y', yPos - 4).text(icon).attr('font-size', '14px').attr('text-anchor', 'start');
        container.append('text').attr('x', 25).attr('y', yPos - 4).text(`${label} : ${val.toFixed(3)}`).attr('fill', color).attr('font-size', '10px').attr('font-weight', 'bold').attr('text-anchor', 'start');
    };
    drawTarget(signal.tpA, '止盈A', '#ef4444', '🎯');
    drawTarget(signal.tpB, '止盈B', '#ef4444', '💰');
    drawTarget(signal.slA, '止损A', '#22c55e', '🛡');
    drawTarget(signal.slB, '止损B', '#22c55e', '🛑');
}

// --- 6. Vol/Price Momentum Painter ---
export function drawVolPriceMomentum(
    container: SelectionGroup,
    data: KlinePoint[],
    x: ScaleBand,
    y: ScaleLinear,
    width: number
) {
    const lastPt = data[data.length-1];

    // 1. Bias Line (Keep as background context)
    const biasData = data.filter(d => d.ma60);
    if (biasData.length > 0) {
        const lineBias = d3.line().x((d: any) => x(d.date)! + x.bandwidth()/2).y((d: any) => y(d.ma60! * 1.05)).curve(d3.curveMonotoneX);
        container.append('path').datum(biasData).attr('fill', 'none').attr('stroke', '#a855f7').attr('stroke-width', 1).attr('stroke-dasharray', '4,4').attr('d', lineBias);
    }

    // 2. Signals & ATR Zone
    for(let i=5; i<data.length; i++) {
        const d = data[i];
        const xPos = x(d.date)! + x.bandwidth()/2;

        // ATR Zone (Background)
        if (d.ma20 && d.atr) {
            const upper = y(d.ma20 + 0.5 * d.atr);
            const lower = y(d.ma20 - 0.5 * d.atr);
            container.append('line').attr('x1', xPos).attr('x2', xPos).attr('y1', upper).attr('y2', lower).attr('stroke', '#cbd5e1').attr('stroke-width', 4).attr('opacity', 0.3);
        }

        // Resonance Logic
        const prev5Vol = data.slice(i-5, i).reduce((sum, item) => sum + item.volume, 0) / 5;
        const volRatio = prev5Vol > 0 ? d.volume / prev5Vol : 0;

        if (d.ma5 && d.ma10 && d.ma20) {
            // Arrow Shapes
            // Buy: Upward Divergence (5>10>20) + Vol > 1.5x
            if (d.ma5 > d.ma10 && d.ma10 > d.ma20 && volRatio > 1.5) {
                // Red Up Arrow
                const yBase = y(d.low) + 20;
                container.append('path')
                    .attr('d', `M 0 -6 L -4 0 L -1.5 0 L -1.5 6 L 1.5 6 L 1.5 0 L 4 0 Z`) // Arrow Path
                    .attr('transform', `translate(${xPos}, ${yBase})`)
                    .attr('fill', '#ef4444')
                    .attr('stroke', '#b91c1c')
                    .attr('stroke-width', 0.5);
            }
            // Sell: Downward Divergence (5<10<20) + Vol > 1.5x
            else if (d.ma5 < d.ma10 && d.ma10 < d.ma20 && volRatio > 1.5) {
                // Green Down Arrow
                const yBase = y(d.low) + 20; // User asked for below K line
                container.append('path')
                    .attr('d', `M 0 6 L -4 0 L -1.5 0 L -1.5 -6 L 1.5 -6 L 1.5 0 L 4 0 Z`) // Arrow Path
                    .attr('transform', `translate(${xPos}, ${yBase})`)
                    .attr('fill', '#22c55e')
                    .attr('stroke', '#15803d')
                    .attr('stroke-width', 0.5);
            }
        }
    }
}

// --- 7. MA Slope Painter ---
export function drawMASlope(
    container: SelectionGroup,
    data: KlinePoint[],
    x: ScaleBand,
    y: ScaleLinear
) {
    for(let i=1; i<data.length; i++) {
        const d = data[i];
        const prev = data[i-1];
        if (d.ma5 && d.ma10 && d.ma20 && prev.ma5 && prev.ma10 && prev.ma20) {
            const s5 = d.ma5 - prev.ma5;
            const s10 = d.ma10 - prev.ma10;
            const s20 = d.ma20 - prev.ma20;
            if (s5 > 0 && s10 > 0 && s20 > 0 && d.ma5 > d.ma10 && d.ma10 > d.ma20) {
                const xPos = x(d.date)! + x.bandwidth()/2;
                const yLow = y(d.low);
                container.append('text').attr('x', xPos).attr('y', yLow + 25).text('⬆️').attr('fill', '#ec4899').attr('font-size', '10px').attr('text-anchor', 'middle');
            }
        }
    }
}

// --- 8. Chan Structure Painter ---
export function drawChanStruct(
    container: SelectionGroup,
    data: KlinePoint[],
    x: ScaleBand,
    y: ScaleLinear
) {
    const fractals: {x: number, y: number, type: 'TOP'|'BTM', date: string}[] = [];
    for(let i=2; i<data.length-2; i++) {
        const d = data[i];
        const l = data[i-1]; const ll = data[i-2];
        const r = data[i+1]; const rr = data[i+2];
        if (d.high > l.high && d.high > ll.high && d.high > r.high && d.high > rr.high) {
            fractals.push({x: x(d.date)! + x.bandwidth()/2, y: y(d.high), type: 'TOP', date: d.date});
        }
        else if (d.low < l.low && d.low < ll.low && d.low < r.low && d.low < rr.low) {
            fractals.push({x: x(d.date)! + x.bandwidth()/2, y: y(d.low), type: 'BTM', date: d.date});
        }
    }
    const strokes: {x: number, y: number}[] = [];
    let lastType: 'TOP' | 'BTM' | null = null;
    fractals.forEach(f => {
        if (lastType === null || lastType !== f.type) {
            strokes.push({x: f.x, y: f.y});
            lastType = f.type;
        } else {
            const lastStroke = strokes[strokes.length-1];
            if (f.type === 'TOP' && f.y < lastStroke.y) { 
                    strokes[strokes.length-1] = {x: f.x, y: f.y};
            } else if (f.type === 'BTM' && f.y > lastStroke.y) { 
                    strokes[strokes.length-1] = {x: f.x, y: f.y};
            }
        }
    });
    if (strokes.length > 1) {
        const lineGen = d3.line().x((d: any) => d.x).y((d: any) => d.y);
        container.append('path').datum(strokes).attr('d', lineGen).attr('fill', 'none').attr('stroke', '#334155').attr('stroke-width', 2);
    }
}

// --- 9. Strategic Buy/Sell Points (R0-R10) Painter ---
export function drawStrategyMarkers(
    container: SelectionGroup,
    data: KlinePoint[],
    x: ScaleBand,
    y: ScaleLinear,
    width: number
) {
    const period = 20;
    let hasPosition = false;
    let entryPrice = 0;
    let entryIndex = -1;
    let waveHigh = -Infinity;
    let waveLow = Infinity;
    let r0Index = -1;

    for (let i = period; i < data.length; i++) {
        const curr = data[i];
        const prev = data[i-1];

        // 1. Calculate Channel
        const slice = data.slice(i - period + 1, i + 1);
        const lr = calculateLR(slice.map((d, idx) => ({ x: idx, y: d.close })));

        let maxDev = -Infinity;
        let minDev = Infinity;
        slice.forEach((d, idx) => {
            const regY = lr.slope * idx + lr.intercept;
            maxDev = Math.max(maxDev, d.high - regY);
            minDev = Math.min(minDev, d.low - regY);
        });

        const currentRegY = lr.slope * (period - 1) + lr.intercept;
        const topChannel = currentRegY + maxDev;
        const bottomChannel = currentRegY + minDev;
        const middleChannel = currentRegY;

        const xPos = x(curr.date)! + x.bandwidth()/2;

        // R0: Observation
        if (!hasPosition && curr.close > topChannel) {
             container.append('text')
                .attr('x', xPos).attr('y', y(curr.high) - 25)
                .text('👁️').attr('font-size', '12px').attr('text-anchor', 'middle')
                .attr('fill', '#a855f7');
             r0Index = i;
        }

        // R1: Entry Logic (Strict)
        // 1. Breakout (Close > Top) recently
        // 2. Vol > 1.5x for 2 days
        // 3. Dip (Close < Prev)
        const volAvg5 = data.slice(i-5, i).reduce((a,b)=>a+b.volume,0)/5;
        const prevVolAvg5 = data.slice(i-6, i-1).reduce((a,b)=>a+b.volume,0)/5;
        const volCond = curr.volume > 1.5 * volAvg5 && prev.volume > 1.5 * prevVolAvg5;
        const breakout = (curr.close > topChannel || prev.close > topChannel);

        if (!hasPosition) {
            if (breakout && volCond && lr.slope > 0) {
                 // Mark Setup
                 container.append('text')
                    .attr('x', xPos).attr('y', y(curr.low) + 20)
                    .text('🚩').attr('font-size', '14px').attr('text-anchor', 'middle');

                 hasPosition = true;
                 entryPrice = curr.close;
                 entryIndex = i;
                 waveHigh = curr.high;
                 waveLow = Math.min(...data.slice(Math.max(0, i-20), i).map(d=>d.low));
            }
        } 
        else {
            // HOLDING STATE
            waveHigh = Math.max(waveHigh, curr.high);
            const range = waveHigh - waveLow;

            // R2: Add Position
            if (i - entryIndex <= 10) {
                 const fib382 = waveHigh - range * 0.382;
                 // Touch Fib + Channel Support + Dip
                 if (curr.low <= fib382 && curr.low >= bottomChannel && curr.close < prev.close) {
                     container.append('text')
                        .attr('x', xPos).attr('y', y(curr.low) + 20)
                        .text('➕').attr('font-size', '12px').attr('text-anchor', 'middle')
                        .attr('fill', '#3b82f6');
                 }
            }

            // R4: Time Warning
            if (i - entryIndex > 20 && curr.high < waveHigh) { 
                 container.append('text')
                    .attr('x', xPos).attr('y', y(curr.high) - 35)
                    .text('⚠️').attr('font-size', '12px').attr('text-anchor', 'middle');
            }

            // R6: Take Profit Levels (Ladder)
            const drop326 = waveHigh - range * 0.326;
            const drop618 = waveHigh - range * 0.618;
            const drop100 = waveHigh - range * 1.0;
            const drop138 = waveHigh - range * 1.382;

            if (curr.close < drop138) { 
                 container.append('text').attr('x', xPos).attr('y', y(curr.high) - 10).text('💰').attr('font-size', '14px').attr('text-anchor', 'middle');
                 hasPosition = false; 
            } else if (curr.close < drop100) {
                 container.append('text').attr('x', xPos).attr('y', y(curr.high) - 10).text('🎯').attr('font-size', '12px').attr('text-anchor', 'middle').attr('fill', '#eab308'); 
            } else if (curr.close < drop618) {
                 container.append('text').attr('x', xPos).attr('y', y(curr.high) - 10).text('🎯').attr('font-size', '12px').attr('text-anchor', 'middle').attr('fill', '#eab308'); 
            } else if (curr.close < drop326) {
                 container.append('text').attr('x', xPos).attr('y', y(curr.high) - 10).text('🎯').attr('font-size', '12px').attr('text-anchor', 'middle').attr('fill', '#ef4444'); 
            }

            // R8: Hard Stop
            if ((curr.close - entryPrice) / entryPrice >= 0.30) {
                 container.append('text').attr('x', xPos).attr('y', y(curr.high) - 25).text('❌').attr('font-size', '14px').attr('text-anchor', 'middle').attr('fill', '#ef4444');
                 hasPosition = false;
            }

            // R9: Defensive Stop
            const stopA = entryPrice - range * 0.326;
            if (curr.close < stopA) {
                container.append('text').attr('x', xPos).attr('y', y(curr.low) + 30).text('🛡️').attr('font-size', '12px').attr('text-anchor', 'middle');
            }

            // R10: Extreme Cut
            const low30 = Math.min(...data.slice(Math.max(0, i-30), i).map(d=>d.low));
            if (curr.close < low30) {
                 container.append('text').attr('x', xPos).attr('y', y(curr.low) + 30).text('🚫').attr('font-size', '14px').attr('text-anchor', 'middle');
                 hasPosition = false;
            }
        }
    }
}
